def utc_now() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def read_text(path: Path) -> str:
    return path.read_text(encoding="utf-8")


def write_json(path: Path, data: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(data, indent=2, sort_keys=False) + "\n", encoding="utf-8")


def append_jsonl(path: Path, rows: list[dict[str, Any]]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text("", encoding="utf-8")
    with path.open("a", encoding="utf-8") as handle:
        for row in rows:
            handle.write(json.dumps(row, sort_keys=False) + "\n")


def load_jsonl(path: Path) -> list[dict[str, Any]]:
    if not path.exists():
        return []

    rows = []
    with path.open("r", encoding="utf-8") as handle:
        for line in handle:
            if not line.strip():
                continue
            rows.append(json.loads(line))
    return rows


def count_jsonl_rows(path: Path) -> int:
    if not path.exists():
        return 0

    rows = 0
    with path.open("r", encoding="utf-8") as handle:
        for line in handle:
            if not line.strip():
                continue
            rows += 1
    return rows


def input_size_limit_message(label: str, size: int, max_input_bytes: int, limit_name: str) -> str:
    return f"{label} is {size} bytes, which exceeds {limit_name}={max_input_bytes}"


def read_text_file_limited(path: Path, *, max_input_bytes: int, limit_name: str) -> str:
    size = path.stat().st_size
    if size > max_input_bytes:
        raise ValueError(input_size_limit_message(str(path), size, max_input_bytes, limit_name))
    return path.read_text(encoding="utf-8")


def read_stdin_limited(*, max_input_bytes: int, limit_name: str) -> str:
    binary_stdin = getattr(sys.stdin, "buffer", None)
    if binary_stdin is not None:
        data = binary_stdin.read(max_input_bytes + 1)
        if len(data) > max_input_bytes:
            raise ValueError(input_size_limit_message("stdin", len(data), max_input_bytes, limit_name))
        return data.decode("utf-8")

    text = sys.stdin.read(max_input_bytes + 1)
    size = len(text.encode("utf-8"))
    if size > max_input_bytes:
        raise ValueError(input_size_limit_message("stdin", size, max_input_bytes, limit_name))
    return text


def load_optional_json(path: Path) -> dict[str, Any] | None:
    return json.loads(read_text(path)) if path.exists() else None


def json_clone(data: Any) -> Any:
    return json.loads(json.dumps(data))


def concrete_local_path_problem(path: Any) -> str | None:
    if not isinstance(path, str):
        return "path must be a string"
    if not path:
        return "path is empty"
    if any(token and token in path for token in MANUAL_PLACEHOLDER_TOKENS):
        return "path still contains a manual REPLACE_WITH_* placeholder"
    parsed = urllib.parse.urlparse(path)
    if parsed.scheme or parsed.netloc:
        return "full URLs are not allowed; use a local path beginning with /"
    if not path.startswith("/") or path.startswith("//"):
        return "path must be a local absolute path beginning with a single /"
    if "{" in path or "}" in path:
        return "path contains template braces and is not concrete"
    if "<" in path or ">" in path:
        return "path contains angle-bracket placeholder text"
    if re.search(r"\s", path):
        return "path contains whitespace"
    return None


def is_active_observation_item(item: dict[str, Any]) -> bool:
    return not (
        item.get("enabled") is False
        or item.get("review_only")
        or item.get("status") == "review-only"
    )


def active_observation_label(item: dict[str, Any], index: int) -> str:
    return str(item.get("id") or f"index-{index}")


