def same_origin_url(url: str, origin: str) -> bool:
    parsed = urllib.parse.urlparse(url)
    parsed_origin = urllib.parse.urlparse(origin)
    return parsed.scheme in {"http", "https"} and parsed.netloc == parsed_origin.netloc


def normalize_allowed_hosts(target: str, extra_hosts: list[str] | None = None) -> set[str]:
    hosts = {urllib.parse.urlparse(target).netloc}
    for item in extra_hosts or []:
        parsed = urllib.parse.urlparse(item if "://" in item else f"https://{item}")
        if parsed.netloc:
            hosts.add(parsed.netloc)
    return {host for host in hosts if host}


def html_script_srcs(html_text: str, page_url: str, *, same_origin_only: bool = True) -> list[str]:
    urls: list[str] = []
    seen: set[str] = set()
    origin = origin_for(page_url)

    def add_url(raw_src: str) -> None:
        raw_src = html.unescape(raw_src.strip())
        if not raw_src or raw_src.startswith(("data:", "blob:", "javascript:")):
            return
        url = urllib.parse.urljoin(page_url, raw_src)
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme not in {"http", "https"}:
            return
        if same_origin_only and not same_origin_url(url, origin):
            return
        if url in seen:
            return
        seen.add(url)
        urls.append(url)

    for match in re.finditer(r"<script\b[^>]*\bsrc\s*=\s*([\"'])(.*?)\1", html_text, flags=re.IGNORECASE | re.DOTALL):
        add_url(match.group(2))
    for tag_match in re.finditer(r"<link\b[^>]*>", html_text, flags=re.IGNORECASE | re.DOTALL):
        tag = tag_match.group(0)
        href_match = re.search(r"\bhref\s*=\s*([\"'])(.*?)\1", tag, flags=re.IGNORECASE | re.DOTALL)
        if not href_match:
            continue
        rel_match = re.search(r"\brel\s*=\s*([\"'])(.*?)\1", tag, flags=re.IGNORECASE | re.DOTALL)
        rel = rel_match.group(2).lower() if rel_match else ""
        href = href_match.group(2).strip()
        href_path = urllib.parse.urlparse(href).path.lower()
        if "modulepreload" in rel or ("preload" in rel and href_path.endswith((".js", ".mjs"))) or href_path.endswith((".js", ".mjs")):
            add_url(href)
    for match in re.finditer(r"(?:\bimport\s*\(|\bfrom\s+)([\"'])(.*?\.(?:js|mjs)(?:\?[^\"']*)?)\1", html_text):
        add_url(match.group(2))
    return urls


def script_url_review_ref(url: str, *, allowed_hosts: set[str]) -> dict[str, Any]:
    parsed = urllib.parse.urlparse(url)
    query_keys = sorted(
        {key for key, _value in urllib.parse.parse_qsl(parsed.query, keep_blank_values=True) if key}
    )
    stripped_query = urllib.parse.urlencode([(key, "") for key in query_keys])
    path = urllib.parse.urlunparse(("", "", redact_url_path(parsed.path or "/"), "", stripped_query, ""))
    return {
        "host": parsed.netloc,
        "path": path,
        "query_keys": query_keys,
        "url_sha256": hashlib.sha256(url.encode("utf-8")).hexdigest(),
        "scope_status": "allowed-host" if parsed.netloc in allowed_hosts else "external-host-review",
    }


def external_script_review_summary(
    script_urls: list[str],
    *,
    page_url: str,
    allowed_hosts: set[str],
    sample_limit: int = 8,
) -> dict[str, Any]:
    page_host = urllib.parse.urlparse(page_url).netloc
    external_urls = [
        url
        for url in script_urls
        if urllib.parse.urlparse(url).netloc and urllib.parse.urlparse(url).netloc != page_host
    ]
    host_counts: dict[str, int] = {}
    scope_status_counts: dict[str, int] = {}
    for url in external_urls:
        ref = script_url_review_ref(url, allowed_hosts=allowed_hosts)
        increment_count(host_counts, str(ref["host"]))
        increment_count(scope_status_counts, str(ref["scope_status"]))
    return {
        "total": len(external_urls),
        "host_counts": dict(sorted(host_counts.items())),
        "scope_status_counts": dict(sorted(scope_status_counts.items())),
        "review_required": any(host not in allowed_hosts for host in host_counts),
        "samples": [
            script_url_review_ref(url, allowed_hosts=allowed_hosts)
            for url in external_urls[:sample_limit]
        ],
        "safety": "External script URLs are recorded for scope review only; blackbox-asset-map does not fetch them.",
    }


ABSOLUTE_URL_RE = re.compile(r"\b(?:https?|wss?)://[^\s\"'<>]+")


def trim_absolute_url_candidate(value: str) -> str:
    return value.rstrip("),.;]}")


def redact_url_path(path: str) -> str:
    segments = []
    for segment in (path or "/").split("/"):
        decoded = urllib.parse.unquote(segment)
        if (
            len(decoded) >= 16
            and re.fullmatch(r"[A-Za-z0-9_-]+", decoded)
            and re.search(r"[A-Za-z]", decoded)
            and re.search(r"[0-9]", decoded)
        ):
            segments.append("{token}")
        else:
            segments.append(segment)
    redacted = "/".join(segments)
    return redacted if redacted.startswith("/") else "/" + redacted


def parent_domain_for_host(host: str) -> str:
    parts = [part for part in host.lower().strip(".").split(".") if part]
    if len(parts) <= 2:
        return ".".join(parts)
    return ".".join(parts[-2:])


def config_host_scope_status(host: str, *, allowed_hosts: set[str], target_host: str) -> str:
    host = host.lower().strip(".")
    if host in allowed_hosts:
        return "allowed-host"
    parent = parent_domain_for_host(target_host)
    if parent and host.endswith("." + parent):
        return "same-parent-domain-review"
    return "external-host-review"


def config_host_role(url: str) -> str:
    parsed = urllib.parse.urlparse(url)
    host = parsed.netloc.lower()
    path = parsed.path.lower()
    if parsed.scheme in {"ws", "wss"}:
        return "websocket-reference"
    if "testnet" in host or "testnet" in path:
        return "testnet-reference"
    if "rpc" in host or "/rpc" in path:
        return "rpc-reference"
    if "quote" in host or "api" in host or "/api" in path:
        return "api-or-service-reference"
    if "static" in host or "cdn" in host or path.endswith((".js", ".mjs", ".css")):
        return "static-asset-reference"
    return "absolute-url-reference"


def config_url_review_ref(
    raw_url: str,
    *,
    source_url: str,
    source_kind: str,
    source_sha256: str,
    line: int | None,
    allowed_hosts: set[str],
    target_host: str,
) -> dict[str, Any] | None:
    value = trim_absolute_url_candidate(html.unescape(str(raw_url or "").strip()))
    parsed = urllib.parse.urlparse(value)
    if parsed.scheme not in {"http", "https", "ws", "wss"} or not parsed.netloc:
        return None
    query_keys = sorted(
        {key for key, _value in urllib.parse.parse_qsl(parsed.query, keep_blank_values=True) if key}
    )
    stripped_query = urllib.parse.urlencode([(key, "") for key in query_keys])
    path = urllib.parse.urlunparse(("", "", redact_url_path(parsed.path or "/"), "", stripped_query, ""))
    host = parsed.netloc.lower().strip(".")
    return {
        "scheme": parsed.scheme,
        "host": host,
        "path": path,
        "query_keys": query_keys,
        "role": config_host_role(value),
        "scope_status": config_host_scope_status(host, allowed_hosts=allowed_hosts, target_host=target_host),
        "source_url": source_url,
        "source_kind": source_kind,
        "source_sha256": source_sha256,
        "line": line,
        "raw_url_sha256": hashlib.sha256(value.encode("utf-8")).hexdigest(),
    }


CONFIG_HOST_PRIORITY_ORDER = {"high": 0, "medium": 1, "low": 2, "info": 3}


def config_host_impact_hypotheses(host: str, scope_status: str, roles: set[str]) -> list[dict[str, Any]]:
    hypotheses: list[dict[str, Any]] = []
    if roles & {"api-or-service-reference", "websocket-reference"}:
        hypotheses.append(
            {
                "impact": "improper-confidential-information-disclosure",
                "severity_floor": "high-if-sensitive-user-data-is-exposed",
                "evidence_needed": "A read-only PoC showing confidential user data for another user or protected account context.",
                "safe_validation_boundary": "Do not authenticate as or act for another user; confirm scope before any request.",
            }
        )
        hypotheses.append(
            {
                "impact": "unauthorized-authenticated-action",
                "severity_floor": "critical-if-actions-are-performed-for-another-user",
                "evidence_needed": "A non-destructive PoC showing an authenticated action can be taken for another user without interaction.",
                "safe_validation_boundary": "No trading, withdrawals, wallet signing, or state-changing requests without explicit authorization.",
            }
        )
    if "rpc-reference" in roles:
        hypotheses.append(
            {
                "impact": "wallet-or-transaction-argument-manipulation",
                "severity_floor": "critical-if-wallet-or-transaction-parameters-can-be-maliciously-changed",
                "evidence_needed": "A local or read-only PoC showing transaction arguments, contract addresses, or wallet interactions can be modified.",
                "safe_validation_boundary": "Do not sign wallets, submit transactions, or use privileged/private keys.",
            }
        )
    if "testnet-reference" in roles:
        hypotheses.append(
            {
                "impact": "production-testnet-boundary-confusion",
                "severity_floor": "informational-unless-production-user-impact-is-demonstrated",
                "evidence_needed": "Evidence that testnet configuration affects production users, funds, orders, or sensitive data.",
                "safe_validation_boundary": "Do not assume testnet impact is in scope; review program scope first.",
            }
        )
    if "static-asset-reference" in roles and scope_status != "allowed-host":
        hypotheses.append(
            {
                "impact": "persistent-static-content-injection",
                "severity_floor": "high-if-persistent-content-can-be-modified-on-target-application",
                "evidence_needed": "A non-destructive PoC showing target application content can be persistently injected or modified.",
                "safe_validation_boundary": "Do not claim, overwrite, upload, or modify third-party/static resources.",
            }
        )
    if scope_status != "allowed-host":
        hypotheses.append(
            {
                "impact": "subdomain-takeover",
                "severity_floor": "high-or-critical-depending-on-wallet-interaction-and-program-impact",
                "evidence_needed": "Provider-specific dangling-domain evidence without claiming or configuring the resource.",
                "safe_validation_boundary": "Use explicit-host DNS/HTTP baselines only; do not enumerate subdomains or claim resources.",
            }
        )
    return hypotheses


def triage_config_host(host: str, scope_status: str, roles: dict[str, int]) -> dict[str, Any]:
    role_set = set(roles)
    if scope_status == "allowed-host":
        return {
            "class": "explicitly-allowed-runtime-host",
            "priority": "info",
            "review_required": False,
            "reason": "Host is already in the explicit allowed host set for this run.",
            "safe_next_step": "Use the existing profile and bounded probe workflow; do not expand scope from this entry alone.",
            "impact_hypotheses": config_host_impact_hypotheses(host, scope_status, role_set),
            "reportability_gate": "Not reportable from configuration reference alone.",
        }

    if role_set & {"rpc-reference", "api-or-service-reference", "websocket-reference"}:
        priority = "high" if scope_status == "same-parent-domain-review" else "medium"
        return {
            "class": "runtime-service-host-review",
            "priority": priority,
            "review_required": True,
            "reason": (
                f"Runtime config references service-like host `{host}` with role(s): "
                + ", ".join(sorted(role_set & {"rpc-reference", "api-or-service-reference", "websocket-reference"}))
            ),
            "safe_next_step": "Confirm bounty scope and read-only semantics before any DNS, HTTP, WebSocket, or API probing.",
            "impact_hypotheses": config_host_impact_hypotheses(host, scope_status, role_set),
            "reportability_gate": "Requires confirmed scope plus PoC for sensitive data exposure, unauthorized action, transaction manipulation, or takeover.",
        }

    if "testnet-reference" in role_set:
        return {
            "class": "testnet-boundary-review",
            "priority": "medium",
            "review_required": True,
            "reason": f"Runtime config references testnet-like host `{host}`; production/testnet boundaries need scope review.",
            "safe_next_step": "Do not probe until the program scope confirms testnet hosts and impact eligibility.",
            "impact_hypotheses": config_host_impact_hypotheses(host, scope_status, role_set),
            "reportability_gate": "Requires demonstrated production user, funds, order, or sensitive-data impact.",
        }

    if "static-asset-reference" in role_set:
        return {
            "class": "static-asset-host-review",
            "priority": "low",
            "review_required": scope_status != "allowed-host",
            "reason": f"Runtime config references static asset host `{host}` outside the explicit allowed host set.",
            "safe_next_step": "Review scope before fetching static assets; prefer local hashes and page references first.",
            "impact_hypotheses": config_host_impact_hypotheses(host, scope_status, role_set),
            "reportability_gate": "Requires proof of persistent target-app content modification or takeover; asset reference alone is not reportable.",
        }

    return {
        "class": "runtime-host-scope-review",
        "priority": "medium" if scope_status == "same-parent-domain-review" else "low",
        "review_required": scope_status != "allowed-host",
        "reason": f"Runtime config references `{host}` outside the explicit allowed host set.",
        "safe_next_step": "Confirm bounty scope and impact hypothesis before any probing.",
        "impact_hypotheses": config_host_impact_hypotheses(host, scope_status, role_set),
        "reportability_gate": "Requires confirmed scope and a concrete in-scope impact PoC.",
    }


def build_config_host_map(
    *,
    target: str,
    sources: list[dict[str, Any]],
    allowed_hosts: set[str],
    sample_limit_per_host: int = 4,
) -> dict[str, Any]:
    target_host = urllib.parse.urlparse(target).netloc.lower()
    host_items: dict[str, dict[str, Any]] = {}
    total_urls = 0
    scheme_counts: dict[str, int] = {}
    scope_status_counts: dict[str, int] = {}
    role_counts: dict[str, int] = {}
    source_kind_counts: dict[str, int] = {}
    impact_hypothesis_counts: dict[str, int] = {}
    reportability_gate_counts: dict[str, int] = {}

    for source in sources:
        text = str(source.get("text") or "")
        source_url = str(source.get("source_url") or source.get("url") or "")
        source_kind = str(source.get("source_kind") or source.get("kind") or "unknown")
        source_sha256 = str(
            source.get("source_sha256")
            or source.get("sha256")
            or hashlib.sha256(text.encode("utf-8", errors="replace")).hexdigest()
        )
        for match in ABSOLUTE_URL_RE.finditer(text):
            line = text.count("\n", 0, match.start()) + 1
            ref = config_url_review_ref(
                match.group(0),
                source_url=source_url,
                source_kind=source_kind,
                source_sha256=source_sha256,
                line=line,
                allowed_hosts=allowed_hosts,
                target_host=target_host,
            )
            if ref is None:
                continue
            total_urls += 1
            increment_count(scheme_counts, str(ref["scheme"]))
            increment_count(scope_status_counts, str(ref["scope_status"]))
            increment_count(role_counts, str(ref["role"]))
            increment_count(source_kind_counts, str(ref["source_kind"]))
            host = str(ref["host"])
            item = host_items.setdefault(
                host,
                {
                    "host": host,
                    "count": 0,
                    "scope_status": ref["scope_status"],
                    "roles": {},
                    "schemes": {},
                    "source_kinds": {},
                    "samples": [],
                },
            )
            item["count"] += 1
            increment_count(item["roles"], str(ref["role"]))
            increment_count(item["schemes"], str(ref["scheme"]))
            increment_count(item["source_kinds"], str(ref["source_kind"]))
            sample = {
                key: ref[key]
                for key in [
                    "scheme",
                    "path",
                    "query_keys",
                    "role",
                    "scope_status",
                    "source_url",
                    "source_kind",
                    "source_sha256",
                    "line",
                    "raw_url_sha256",
                ]
            }
            if len(item["samples"]) < sample_limit_per_host and sample not in item["samples"]:
                item["samples"].append(sample)

    review_hosts = [
        host
        for host, item in host_items.items()
        if item.get("scope_status") != "allowed-host"
    ]
    triage_class_counts: dict[str, int] = {}
    triage_priority_counts: dict[str, int] = {}
    for item in host_items.values():
        triage = triage_config_host(
            str(item.get("host") or ""),
            str(item.get("scope_status") or ""),
            item.get("roles", {}) if isinstance(item.get("roles"), dict) else {},
        )
        item["triage"] = triage
        increment_count(triage_class_counts, str(triage["class"]))
        increment_count(triage_priority_counts, str(triage["priority"]))
        for hypothesis in triage.get("impact_hypotheses", []) or []:
            if isinstance(hypothesis, dict) and hypothesis.get("impact"):
                increment_count(impact_hypothesis_counts, str(hypothesis["impact"]))
        if triage.get("reportability_gate"):
            increment_count(reportability_gate_counts, str(triage["reportability_gate"]))
    return {
        "generated_at": utc_now(),
        "status": "review-required" if review_hosts else "complete",
        "target": target,
        "allowed_hosts": sorted(allowed_hosts),
        "summary": {
            "absolute_url_count": total_urls,
            "host_count": len(host_items),
            "review_host_count": len(review_hosts),
            "scheme_counts": dict(sorted(scheme_counts.items())),
            "scope_status_counts": dict(sorted(scope_status_counts.items())),
            "role_counts": dict(sorted(role_counts.items())),
            "source_kind_counts": dict(sorted(source_kind_counts.items())),
            "triage_class_counts": dict(sorted(triage_class_counts.items())),
            "triage_priority_counts": dict(sorted(triage_priority_counts.items())),
            "impact_hypothesis_counts": dict(sorted(impact_hypothesis_counts.items())),
            "reportability_gate_counts": dict(sorted(reportability_gate_counts.items())),
        },
        "hosts": sorted(
            host_items.values(),
            key=lambda item: (
                CONFIG_HOST_PRIORITY_ORDER.get(str(item.get("triage", {}).get("priority")), 99),
                item.get("scope_status") == "allowed-host",
                str(item.get("host")),
            ),
        ),
        "safety": "Passive URL host map only. Query values and response bodies are not stored, and referenced hosts are not requested by this artifact.",
    }


