def normalize_explicit_hosts(target: str, host_values: list[str] | None, *, max_hosts: int = 8) -> list[str]:
    raw_hosts = host_values or [urllib.parse.urlparse(target).netloc]
    hosts: list[str] = []
    for raw in raw_hosts:
        parsed = urllib.parse.urlparse(raw if "://" in raw else f"https://{raw}")
        host = parsed.netloc or parsed.path
        host = host.split("@")[-1].split(":")[0].strip().lower().rstrip(".")
        if not host or "*" in host or "/" in host:
            raise ValueError(f"host must be explicit, not wildcard or path-like: {raw}")
        if host not in hosts:
            hosts.append(host)
        if len(hosts) > max_hosts:
            raise ValueError(f"too many hosts for low-volume takeover baseline: max {max_hosts}")
    return hosts


def dig_short_records(host: str, rrtype: str, *, timeout: int) -> dict[str, Any]:
    command = ["dig", f"+time={max(1, timeout)}", "+tries=1", "+short", rrtype, host]
    try:
        completed = subprocess.run(
            command,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=max(2, timeout + 1),
            check=False,
        )
    except (FileNotFoundError, subprocess.TimeoutExpired) as error:
        return {
            "records": [],
            "error": redacted_error_summary(error),
            "resolver": "dig",
        }
    records = [line.strip() for line in completed.stdout.splitlines() if line.strip()]
    return {
        "records": records,
        "error": redacted_error_summary(completed.stderr) if completed.returncode and completed.stderr else None,
        "resolver": "dig",
    }


def dns_records_for_host(host: str, *, timeout: int) -> dict[str, Any]:
    cname_raw = dig_short_records(host, "CNAME", timeout=timeout)
    a_raw = dig_short_records(host, "A", timeout=timeout)
    aaaa_raw = dig_short_records(host, "AAAA", timeout=timeout)

    def ip_records(rows: list[str], version: int) -> list[str]:
        output: list[str] = []
        for row in rows:
            try:
                parsed_ip = ipaddress.ip_address(row)
            except ValueError:
                continue
            if parsed_ip.version == version:
                output.append(str(parsed_ip))
        return output

    return {
        "cname": [row.lower().rstrip(".") for row in cname_raw["records"] if not re.match(r"^[0-9a-fA-F:.]+$", row)],
        "a": ip_records(a_raw["records"], 4),
        "aaaa": ip_records(aaaa_raw["records"], 6),
        "errors": {
            "cname": cname_raw.get("error"),
            "a": a_raw.get("error"),
            "aaaa": aaaa_raw.get("error"),
        },
    }


def takeover_provider_hints(cnames: list[str]) -> list[dict[str, Any]]:
    hints = []
    for cname in cnames:
        for suffix, provider in TAKEOVER_CNAME_PROVIDER_SUFFIXES.items():
            if cname == suffix or cname.endswith("." + suffix):
                hints.append({"provider": provider, "cname": cname, "suffix": suffix})
    return hints


def takeover_http_fingerprints(body_text: str) -> list[dict[str, Any]]:
    lowered = body_text.lower()
    matches = []
    for fingerprint in TAKEOVER_HTTP_FINGERPRINTS:
        markers = fingerprint["markers"]
        if all(marker in lowered for marker in markers):
            matches.append(
                {
                    "provider": fingerprint["provider"],
                    "confidence": fingerprint["confidence"],
                    "markers_sha256": hashlib.sha256("|".join(markers).encode("utf-8")).hexdigest(),
                }
            )
    return matches


def build_host_takeover_baseline(
    *,
    target: str,
    hosts: list[str],
    include_http: bool,
    timeout: int,
    max_bytes: int,
) -> dict[str, Any]:
    rows = []
    for host in hosts:
        dns = dns_records_for_host(host, timeout=timeout)
        provider_hints = takeover_provider_hints(dns.get("cname", []))
        http_summary = None
        fingerprints: list[dict[str, Any]] = []
        if include_http:
            response = http_get_url_text_limited(
                f"https://{host}/",
                timeout=timeout,
                max_bytes=max_bytes,
                user_agent="InferForge-Host-Takeover-Baseline/0.1",
            )
            fingerprints = takeover_http_fingerprints(str(response.get("text") or ""))
            headers = response.get("headers", {}) if isinstance(response.get("headers"), dict) else {}
            body = str(response.get("text") or "").encode("utf-8", errors="replace")
            http_summary = {
                "url": f"https://{host}/",
                "status": response.get("status"),
                "ok": response.get("ok"),
                "duration_ms": response.get("duration_ms"),
                "bytes": response.get("bytes"),
                "body_sha256": hashlib.sha256(body).hexdigest() if body else response.get("sha256"),
                "body_truncated": response.get("truncated"),
                "content_type": headers.get("Content-Type") or headers.get("content-type"),
                "server": headers.get("Server") or headers.get("server"),
                "error": redacted_error_summary(response.get("error")) if response.get("error") else None,
            }
        status = "takeover-signal" if fingerprints else "no-takeover-signal"
        rows.append(
            {
                "host": host,
                "status": status,
                "dns": dns,
                "provider_hints": provider_hints,
                "http": http_summary,
                "fingerprints": fingerprints,
                "review_required": bool(fingerprints),
            }
        )
    signal_rows = [row for row in rows if row.get("review_required")]
    return {
        "generated_at": utc_now(),
        "status": "needs-human-review" if signal_rows else "complete",
        "target": target,
        "hosts_checked": hosts,
        "summary": {
            "hosts": len(rows),
            "takeover_signals": len(signal_rows),
            "provider_hint_hosts": sum(1 for row in rows if row.get("provider_hints")),
            "http_checked": include_http,
            "max_bytes": max_bytes if include_http else 0,
        },
        "hosts": rows,
        "safety": "Explicit-host takeover baseline only. It does not enumerate subdomains, fuzz DNS, request candidate endpoints, or store response bodies.",
    }


def strip_query_values(path: str) -> tuple[str, list[str]]:
    parsed = urllib.parse.urlparse(path)
    query_keys = sorted({key for key, _value in urllib.parse.parse_qsl(parsed.query, keep_blank_values=True) if key})
    query = urllib.parse.urlencode([(key, "") for key in query_keys])
    stripped = urllib.parse.urlunparse(("", "", parsed.path or "/", "", query, ""))
    return stripped, query_keys


def normalize_asset_candidate_url(raw_value: str, *, base_url: str, allowed_hosts: set[str]) -> dict[str, Any] | None:
    value = html.unescape(str(raw_value or "").strip())
    if not value or value.startswith(("data:", "blob:", "javascript:", "mailto:", "#")):
        return None
    if "${" in value:
        value = re.sub(r"\$\{[^}]+\}", "{param}", value)
    if not value.startswith(("/", "http://", "https://", "ws://", "wss://")):
        if re.match(r"^(api|v[0-9]+|graphql|ws|socket|quote|spot|perp|order|account|trade|markets?)/", value):
            value = "/" + value
        else:
            return None

    absolute = urllib.parse.urljoin(base_url, value)
    parsed = urllib.parse.urlparse(absolute)
    if parsed.scheme not in {"http", "https", "ws", "wss"}:
        return None
    if parsed.netloc and parsed.netloc not in allowed_hosts:
        return None
    if is_static_asset_path(parsed.path or "/"):
        return None

    path, query_keys = strip_query_values(urllib.parse.urlunparse(("", "", parsed.path or "/", "", parsed.query, "")))
    lower_path = (parsed.path or "/").lower()
    lower_value = value.lower()
    endpoint_like = (
        lower_path.startswith(BLACKBOX_ASSET_ENDPOINT_PREFIXES)
        or any(token in lower_path for token in BLACKBOX_ASSET_ENDPOINT_TOKENS)
        or parsed.scheme in {"ws", "wss"}
        or any(token in lower_value for token in ("api.", "quote.", "spot.", "perp."))
    )
    if not endpoint_like:
        return None

    return {
        "scheme": parsed.scheme,
        "host": parsed.netloc,
        "path": path,
        "path_without_query": urllib.parse.urlparse(path).path or "/",
        "query_keys": query_keys,
        "kind": "websocket-candidate" if parsed.scheme in {"ws", "wss"} or "ws" in lower_path or "socket" in lower_path else "http-candidate",
        "raw_value_sha256": hashlib.sha256(value.encode("utf-8", errors="replace")).hexdigest(),
    }


def iter_javascript_string_literals(source: str) -> Iterator[tuple[str, int, int]]:
    index = 0
    while index < len(source):
        quote = source[index]
        if quote not in {"'", '"', "`"}:
            index += 1
            continue
        start = index
        index += 1
        escaped = False
        chars: list[str] = []
        while index < len(source):
            char = source[index]
            if escaped:
                chars.append("\\" + char)
                escaped = False
                index += 1
                continue
            if char == "\\":
                escaped = True
                index += 1
                continue
            if char == quote:
                raw_fragment = "".join(chars)
                yield decode_loose_json_string_fragment(raw_fragment), start, index + 1
                index += 1
                break
            chars.append(char)
            index += 1
        else:
            break


def method_hint_near_literal(source: str, start: int, end: int) -> str | None:
    prefix = source[max(0, start - 80) : start]
    for method in ["DELETE", "PATCH", "POST", "PUT", "GET", "HEAD", "OPTIONS"]:
        if re.search(rf"\b(?:axios|client|http|request)\s*\.\s*{method.lower()}\s*\([^()\n]*$", prefix):
            return method
    window = source[max(0, start - 180) : min(len(source), end + 180)]
    for method in ["DELETE", "PATCH", "POST", "PUT", "GET", "HEAD", "OPTIONS"]:
        if re.search(rf"\bmethod\s*[:=]\s*['\"]{method}['\"]", window, flags=re.IGNORECASE):
            return method
        if re.search(rf"\b(?:axios|client|http|request)\s*\.\s*{method.lower()}\s*\(", window):
            return method
    if "new WebSocket" in window or "WebSocket(" in window:
        return "WS"
    return None


def triage_blackbox_asset_candidate(candidate: dict[str, Any], method_hint: str | None) -> dict[str, Any]:
    method = "WS" if candidate.get("kind") == "websocket-candidate" else (method_hint or "UNKNOWN")
    path = str(candidate.get("path_without_query") or candidate.get("path") or "/")
    lower_path = path.lower()
    api_like = lower_path.startswith(("/api", "/v1", "/v2", "/v3", "/graphql"))
    state_tokens = {
        "order",
        "orders",
        "trade",
        "position",
        "positions",
        "account",
        "wallet",
        "withdraw",
        "deposit",
        "transfer",
        "auth",
        "login",
        "session",
    }
    path_words = set(re.findall(r"[a-z0-9]+", lower_path))
    sensitive_tokens = sorted(path_words & state_tokens)

    if method == "WS":
        return {
            "class": "websocket-handshake-review",
            "risk": "medium",
            "active_probe_policy": "handshake-only-after-review",
            "reason": "WebSocket candidate extracted from static assets; review scope and message semantics before sending frames.",
            "safe_next_step": "If in scope, perform at most one handshake-only connection without subscriptions or messages.",
        }

    if method in {"POST", "PUT", "PATCH", "DELETE"}:
        return {
            "class": "state-changing-api-review",
            "risk": "high",
            "active_probe_policy": "manual-review-required",
            "reason": f"Method hint `{method}` may mutate state or touch business operations.",
            "safe_next_step": "Do not probe automatically; review auth, account, order, and transaction semantics first.",
        }

    if api_like and sensitive_tokens:
        return {
            "class": "sensitive-api-review",
            "risk": "high",
            "active_probe_policy": "manual-review-required",
            "reason": f"API-like path contains sensitive token(s): {', '.join(sensitive_tokens)}.",
            "safe_next_step": "Do not probe automatically; derive a read-only reproduction plan before any request.",
        }

    if api_like:
        return {
            "class": "api-read-candidate-review",
            "risk": "medium",
            "active_probe_policy": "head-or-get-after-review",
            "reason": "API-like candidate without a state-changing method hint still needs scope and auth-context review.",
            "safe_next_step": "Promote only if the endpoint is known read-only and in scope; prefer HEAD before GET.",
        }

    return {
        "class": "passive-page-route-review",
        "risk": "low",
        "active_probe_policy": "head-or-get-after-review",
        "reason": "Page-route-like candidate without API or mutation method hints.",
        "safe_next_step": "After scope review, this can usually be promoted as a low-risk HEAD/GET page-route candidate.",
    }


def add_asset_candidate(
    candidates: dict[tuple[str, str, str], dict[str, Any]],
    *,
    candidate: dict[str, Any],
    source_url: str,
    source_kind: str,
    source_sha256: str,
    line: int | None,
    method_hint: str | None,
) -> None:
    method = "WS" if candidate.get("kind") == "websocket-candidate" else (method_hint or "UNKNOWN")
    key = (method, str(candidate.get("host") or ""), str(candidate.get("path") or "/"))
    triage = triage_blackbox_asset_candidate(candidate, method_hint)
    item = candidates.setdefault(
        key,
        {
            "id": f"asset-{safe_probe_id(method)}-{safe_probe_id(candidate.get('host') or 'same-origin')}-{safe_probe_id(candidate.get('path') or 'root')}",
            "method_hint": method,
            "host": candidate.get("host"),
            "path": candidate.get("path"),
            "path_without_query": candidate.get("path_without_query"),
            "query_keys": candidate.get("query_keys", []),
            "kind": candidate.get("kind"),
            "sources": [],
            "risk": "review-required",
            "triage": triage,
            "review_note": "Static asset candidate only. Do not probe until scope, auth context, and business impact are reviewed.",
        },
    )
    source_ref = {
        "source_url": source_url,
        "source_kind": source_kind,
        "source_sha256": source_sha256,
        "line": line,
        "raw_value_sha256": candidate.get("raw_value_sha256"),
    }
    if source_ref not in item["sources"]:
        item["sources"].append(source_ref)


def extract_blackbox_asset_candidates_from_text(
    source: str,
    *,
    source_url: str,
    source_kind: str,
    base_url: str,
    allowed_hosts: set[str],
    candidate_limit: int | None = None,
) -> list[dict[str, Any]]:
    source_sha256 = hashlib.sha256(source.encode("utf-8", errors="replace")).hexdigest()
    candidates: dict[tuple[str, str, str], dict[str, Any]] = {}

    def limit_reached() -> bool:
        return candidate_limit is not None and len(candidates) >= candidate_limit

    for value, start, end in iter_javascript_string_literals(source):
        if limit_reached():
            break
        candidate = normalize_asset_candidate_url(value, base_url=base_url, allowed_hosts=allowed_hosts)
        if candidate is None:
            continue
        line = source.count("\n", 0, start) + 1
        add_asset_candidate(
            candidates,
            candidate=candidate,
            source_url=source_url,
            source_kind=source_kind,
            source_sha256=source_sha256,
            line=line,
            method_hint=method_hint_near_literal(source, start, end),
        )

    url_pattern = re.compile(r"\b(?:https?|wss?)://[A-Za-z0-9._~:/?#\[\]@!$&'()*+,;=%-]+")
    for match in url_pattern.finditer(source):
        if limit_reached():
            break
        candidate = normalize_asset_candidate_url(match.group(0), base_url=base_url, allowed_hosts=allowed_hosts)
        if candidate is None:
            continue
        line = source.count("\n", 0, match.start()) + 1
        add_asset_candidate(
            candidates,
            candidate=candidate,
            source_url=source_url,
            source_kind=source_kind,
            source_sha256=source_sha256,
            line=line,
            method_hint=method_hint_near_literal(source, match.start(), match.end()),
        )
    return sorted(candidates.values(), key=lambda item: (item.get("host") or "", item.get("path") or "", item.get("method_hint") or ""))


def http_get_url_text_limited(url: str, *, timeout: int, max_bytes: int, user_agent: str) -> dict[str, Any]:
    started = time.monotonic()
    request = urllib.request.Request(url, method="GET", headers={"User-Agent": user_agent})
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            body = response.read(max_bytes + 1)
            headers = dict(response.headers.items())
            status = response.status
    except urllib.error.HTTPError as error:
        body = error.read(max_bytes + 1)
        headers = dict(error.headers.items())
        status = error.code
    except (urllib.error.URLError, TimeoutError, socket.timeout) as error:
        return {
            "ok": False,
            "url": url,
            "status": None,
            "duration_ms": round((time.monotonic() - started) * 1000),
            "error": str(getattr(error, "reason", error)),
            "text": "",
            "bytes": 0,
            "sha256": None,
            "truncated": False,
            "headers": {},
        }
    truncated = len(body) > max_bytes
    if truncated:
        body = body[:max_bytes]
    return {
        "ok": True,
        "url": url,
        "status": status,
        "duration_ms": round((time.monotonic() - started) * 1000),
        "error": None,
        "text": body.decode("utf-8", errors="replace"),
        "bytes": len(body),
        "sha256": hashlib.sha256(body).hexdigest(),
        "truncated": truncated,
        "headers": headers,
    }


def merge_asset_candidates(candidate_lists: list[list[dict[str, Any]]]) -> list[dict[str, Any]]:
    merged: dict[tuple[str, str, str], dict[str, Any]] = {}
    for candidates in candidate_lists:
        for candidate in candidates:
            key = (
                str(candidate.get("method_hint") or ""),
                str(candidate.get("host") or ""),
                str(candidate.get("path") or ""),
            )
            item = merged.setdefault(key, json_clone(candidate))
            for source_ref in candidate.get("sources", []) or []:
                if source_ref not in item["sources"]:
                    item["sources"].append(source_ref)
    return sorted(merged.values(), key=lambda item: (item.get("host") or "", item.get("path") or "", item.get("method_hint") or ""))


def build_blackbox_asset_map(
    *,
    target: str,
    page_url: str,
    page_fetch: dict[str, Any] | None,
    page_text: str,
    assets: list[dict[str, Any]],
    allowed_hosts: set[str],
    max_assets: int,
    candidate_limit: int | None = None,
) -> dict[str, Any]:
    all_script_urls = html_script_srcs(page_text, page_url, same_origin_only=False)
    script_urls = html_script_srcs(page_text, page_url, same_origin_only=True)
    external_scripts = external_script_review_summary(
        all_script_urls,
        page_url=page_url,
        allowed_hosts=allowed_hosts,
    )
    config_sources = [
        {
            "text": page_text,
            "source_url": page_url,
            "source_kind": "html",
            "source_sha256": hashlib.sha256(page_text.encode("utf-8", errors="replace")).hexdigest(),
        }
    ]
    for asset in assets:
        config_sources.append(
            {
                "text": str(asset.get("text") or ""),
                "source_url": str(asset.get("url") or ""),
                "source_kind": "script",
                "source_sha256": str(asset.get("sha256") or ""),
            }
        )
    config_hosts = build_config_host_map(
        target=target,
        sources=config_sources,
        allowed_hosts=allowed_hosts,
    )
    candidate_lists = [
        extract_blackbox_asset_candidates_from_text(
            page_text,
            source_url=page_url,
            source_kind="html",
            base_url=page_url,
            allowed_hosts=allowed_hosts,
            candidate_limit=candidate_limit,
        )
    ]
    asset_summaries = []
    for asset in assets:
        text = str(asset.get("text") or "")
        current_count = sum(len(candidates) for candidates in candidate_lists)
        remaining_limit = None if candidate_limit is None else max(0, candidate_limit - current_count)
        if remaining_limit == 0:
            text = ""
        candidate_lists.append(
            extract_blackbox_asset_candidates_from_text(
                text,
                source_url=str(asset.get("url") or ""),
                source_kind="script",
                base_url=str(asset.get("url") or page_url),
                allowed_hosts=allowed_hosts,
                candidate_limit=remaining_limit,
            )
        )
        headers = asset.get("headers", {}) if isinstance(asset.get("headers"), dict) else {}
        asset_summaries.append(
            {
                "url": asset.get("url"),
                "status": asset.get("status"),
                "bytes": asset.get("bytes"),
                "sha256": asset.get("sha256"),
                "truncated": asset.get("truncated"),
                "content_type": headers.get("Content-Type") or headers.get("content-type"),
                "duration_ms": asset.get("duration_ms"),
                "error": redacted_error_summary(Exception(str(asset.get("error")))) if asset.get("error") else None,
            }
        )
    candidates = merge_asset_candidates(candidate_lists)
    triage_class_counts: dict[str, int] = {}
    triage_risk_counts: dict[str, int] = {}
    for candidate in candidates:
        triage = candidate.get("triage", {}) if isinstance(candidate.get("triage"), dict) else {}
        increment_count(triage_class_counts, str(triage.get("class") or "unknown"))
        increment_count(triage_risk_counts, str(triage.get("risk") or candidate.get("risk") or "unknown"))
    page_headers = page_fetch.get("headers", {}) if isinstance(page_fetch, dict) and isinstance(page_fetch.get("headers"), dict) else {}
    return {
        "generated_at": utc_now(),
        "status": "candidates-found" if candidates else "no-candidates",
        "target": target,
        "page": {
            "url": page_url,
            "status": None if page_fetch is None else page_fetch.get("status"),
            "bytes": len(page_text.encode("utf-8", errors="replace")) if page_fetch is None else page_fetch.get("bytes"),
            "sha256": hashlib.sha256(page_text.encode("utf-8", errors="replace")).hexdigest(),
            "content_type": page_headers.get("Content-Type") or page_headers.get("content-type"),
            "script_urls_seen": len(all_script_urls),
            "same_origin_script_urls_seen": len(script_urls),
            "external_script_urls_seen": external_scripts["total"],
            "script_urls_considered": min(len(script_urls), max_assets),
        },
        "allowed_hosts": sorted(allowed_hosts),
        "assets": asset_summaries,
        "external_scripts": external_scripts,
        "config_hosts": config_hosts,
        "summary": {
            "assets_fetched": len(assets),
            "candidates": len(candidates),
            "http_candidates": sum(1 for item in candidates if item.get("kind") == "http-candidate"),
            "websocket_candidates": sum(1 for item in candidates if item.get("kind") == "websocket-candidate"),
            "post_hints": sum(1 for item in candidates if item.get("method_hint") == "POST"),
            "review_required": len(candidates),
            "external_script_urls_seen": external_scripts["total"],
            "external_script_hosts": len(external_scripts["host_counts"]),
            "external_script_review_required": bool(external_scripts["review_required"]),
            "config_host_count": config_hosts["summary"]["host_count"],
            "config_review_host_count": config_hosts["summary"]["review_host_count"],
            "candidate_limit": candidate_limit,
            "candidate_limit_reached": candidate_limit is not None and len(candidates) >= candidate_limit,
            "triage_class_counts": triage_class_counts,
            "triage_risk_counts": triage_risk_counts,
        },
        "candidates": candidates,
        "safety": [
            "Low-volume static asset mapping only; candidate endpoints are not requested.",
            "Only the target page and same-origin script assets are fetched by this command.",
            "Raw HTML and JavaScript bodies are not persisted; artifacts store paths, query keys, hashes, and source URLs only.",
            "Query values are stripped from candidate paths.",
        ],
    }


def build_blackbox_profile_from_asset_candidates(
    candidate_doc: dict[str, Any],
    *,
    name: str,
    display_name: str,
    target: str,
    allowed_classes: set[str],
    max_endpoints: int | None = None,
    collapse_route_variants: bool = True,
) -> tuple[dict[str, Any], dict[str, Any]]:
    target_netloc = urllib.parse.urlparse(target).netloc.lower()
    by_path: dict[str, dict[str, Any]] = {}
    skipped = {
        "other_host": 0,
        "non_http": 0,
        "triage_class": 0,
        "unsafe_method": 0,
        "static_asset": 0,
        "route_family_duplicate": 0,
    }

    for candidate in candidate_doc.get("candidates", []) or []:
        if not isinstance(candidate, dict):
            continue
        host = str(candidate.get("host") or target_netloc).lower()
        if target_netloc and host != target_netloc:
            skipped["other_host"] += 1
            continue
        if candidate.get("kind") != "http-candidate":
            skipped["non_http"] += 1
            continue
        triage = candidate.get("triage", {}) if isinstance(candidate.get("triage"), dict) else {}
        triage_class = str(triage.get("class") or "")
        if triage_class not in allowed_classes:
            skipped["triage_class"] += 1
            continue
        method_hint = str(candidate.get("method_hint") or "").upper()
        if method_hint in {"", "UNKNOWN"}:
            method = "GET"
        elif method_hint in {"GET", "HEAD"}:
            method = method_hint
        else:
            skipped["unsafe_method"] += 1
            continue
        path = blackbox_profile_path(candidate.get("path"))
        if is_static_asset_path(path):
            skipped["static_asset"] += 1
            continue
        item = by_path.setdefault(
            path,
            {
                "path": path,
                "methods": set(),
                "hosts": set(),
                "query_keys": set(),
                "source_candidate_ids": [],
                "triage_classes": set(),
                "triage_risks": set(),
                "source_count": 0,
            },
        )
        item["methods"].add(method)
        item["hosts"].add(host)
        item["query_keys"].update(str(key) for key in candidate.get("query_keys", []) or [] if str(key))
        candidate_id = str(candidate.get("id") or "")
        if candidate_id and candidate_id not in item["source_candidate_ids"]:
            item["source_candidate_ids"].append(candidate_id)
        if triage_class:
            item["triage_classes"].add(triage_class)
        if triage.get("risk"):
            item["triage_risks"].add(str(triage.get("risk")))
        item["source_count"] += len(candidate.get("sources", []) or [])

    rows = sorted(
        by_path.values(),
        key=lambda item: (
            item["path"],
        ),
    )
    route_families: list[dict[str, Any]] = []
    if collapse_route_variants:
        grouped: dict[str, list[dict[str, Any]]] = {}
        for item in rows:
            family_path, _locale = blackbox_route_family(str(item["path"]))
            grouped.setdefault(family_path, []).append(item)

        collapsed_rows: list[dict[str, Any]] = []
        for family_path in sorted(grouped):
            items = grouped[family_path]
            representative = sorted(items, key=lambda item: blackbox_route_variant_rank(str(item["path"])))[0]
            variants = sorted(str(item["path"]) for item in items)
            locales = sorted(
                locale
                for item in items
                for _family, locale in [blackbox_route_family(str(item["path"]))]
                if locale
            )
            merged = {
                "path": str(representative["path"]),
                "methods": set().union(*(set(item["methods"]) for item in items)),
                "hosts": set().union(*(set(item["hosts"]) for item in items)),
                "query_keys": set().union(*(set(item["query_keys"]) for item in items)),
                "source_candidate_ids": [],
                "triage_classes": set().union(*(set(item["triage_classes"]) for item in items)),
                "triage_risks": set().union(*(set(item["triage_risks"]) for item in items)),
                "source_count": sum(int(item["source_count"]) for item in items),
                "route_family": {
                    "family_path": family_path,
                    "representative_path": str(representative["path"]),
                    "variants": variants,
                    "locales": locales,
                    "collapsed_variant_count": max(0, len(items) - 1),
                },
            }
            for item in items:
                for candidate_id in item["source_candidate_ids"]:
                    if candidate_id not in merged["source_candidate_ids"]:
                        merged["source_candidate_ids"].append(candidate_id)
            collapsed_rows.append(merged)
            skipped["route_family_duplicate"] += max(0, len(items) - 1)
            if len(items) > 1:
                route_families.append(merged["route_family"])
        rows = collapsed_rows
    if max_endpoints is not None:
        rows = rows[:max_endpoints]

    clusters: list[dict[str, Any]] = []
    probe_targets: dict[str, Any] = {}
    endpoint_summaries: list[dict[str, Any]] = []
    burp_observation_plan: list[dict[str, Any]] = []
    for item in rows:
        path = str(item["path"])
        methods = sorted(
            {str(method) for method in item["methods"]},
            key=lambda method: (HTTP_METHOD_ORDER_INDEX.get(method, 99), method),
        )
        cluster_id = blackbox_cluster_id_for_path(path)
        query_keys = sorted(str(key) for key in item["query_keys"])
        cluster = {
            "id": cluster_id,
            "method": methods[0] if methods else "GET",
            "path": path,
            "kind": "asset-discovered-page-route",
            "priority": "low",
            "strategy_set": "blackbox-http-observed",
            "match": {"methods": methods or ["GET"], "paths": [path]},
            "source_refs": [],
            "discovery": {
                "source": BLACKBOX_ASSET_CANDIDATES_ARTIFACT,
                "review_status": "reviewed-low-risk-promotion",
                "active_probe_policy": "head-or-get-after-review",
                "source_candidate_ids": item["source_candidate_ids"],
                "query_keys": query_keys,
                "hosts": sorted(str(host) for host in item["hosts"]),
                "triage_classes": sorted(str(value) for value in item["triage_classes"]),
                "triage_risks": sorted(str(value) for value in item["triage_risks"]),
                "source_count": int(item["source_count"]),
                "route_family": item.get("route_family"),
                "notes": [
                    "Generated from reviewed static asset candidates.",
                    "Only low-risk page-route candidates are promoted by default.",
                    "Query values are intentionally not copied into the profile.",
                    "Run plan --no-write before any active probes.",
                ],
            },
        }
        clusters.append(cluster)
        probe_targets[cluster_id] = {"path": path}
        burp_observation_plan.append(
            {
                "id": f"burp_observe_{safe_probe_id(cluster_id)}",
                "method": "HEAD",
                "path": path,
                "headers": {"User-Agent": "InferForge-Burp-Observe/0.1"},
                "expected_statuses": [200, 204, 301, 302, 307, 308, 400, 403, 404, 405],
                "cluster": cluster_id,
            }
        )
        endpoint_summaries.append(
            {
                "cluster_id": cluster_id,
                "path": path,
                "methods": methods,
                "query_keys": query_keys,
                "source_candidate_ids": item["source_candidate_ids"],
                "triage_classes": sorted(str(value) for value in item["triage_classes"]),
                "route_family": item.get("route_family"),
            }
        )

    profile = {
        "schema_version": 1,
        "name": name,
        "display_name": display_name,
        "description": "Pure black-box target profile generated from reviewed static asset endpoint candidates. Review scope before active probes.",
        "assessment_mode": "blackbox",
        "target_type": "blackbox-web-app",
        "frameworks": [],
        "default_target": target,
        "default_source_root": ".",
        "strategy_sets": ["blackbox-http-observed"],
        "safety": {
            "no_wallet_signing": True,
            "no_transaction_submission": True,
            "no_burp_scanner": True,
            "no_broad_fuzzing": True,
            "prefer_loopback_targets": False,
            "requires_bounty_scope_review": True,
            "asset_candidates_profile": True,
        },
        "probe_targets": probe_targets,
        "quote_intent": {},
        "quote_request": {},
        "quote_response": {},
        "quote_provider": {},
        "environment_readiness": {"checks": []},
        "clusters": clusters,
        "source_peeks": [],
        "burp_observation_plan": burp_observation_plan,
        "review_observation_candidates": [],
        "websocket_observation": None,
        "blackbox": {
            "generated_at": utc_now(),
            "history_source": BLACKBOX_ASSET_CANDIDATES_ARTIFACT,
            "asset_candidate_profile": True,
            "allowed_triage_classes": sorted(allowed_classes),
            "observed_endpoint_count": 0,
            "asset_endpoint_count": len(clusters),
            "burp_observation_count": len(burp_observation_plan),
            "max_endpoints": max_endpoints,
            "collapse_route_variants": collapse_route_variants,
            "skipped": skipped,
            "workflow": [
                "Run blackbox-asset-map to refresh static asset candidates.",
                "Run blackbox-asset-profile to promote reviewed low-risk page-route candidates.",
                "Run plan --no-write with this profile before any active probes.",
                "Keep API, WebSocket, and mutation-sensitive candidates in manual review until a safe reproduction plan exists.",
            ],
        },
    }
    summary = {
        "generated_at": utc_now(),
        "status": "generated" if clusters else "no-promoted-candidates",
        "target": target,
        "profile": {"name": name, "display_name": display_name},
        "input_candidates": len(candidate_doc.get("candidates", []) or []),
        "generated_clusters": len(clusters),
        "generated_burp_observations": len(burp_observation_plan),
        "allowed_triage_classes": sorted(allowed_classes),
        "skipped": skipped,
        "route_families": route_families,
        "endpoints": endpoint_summaries,
        "safety": "Profile generation is read-only over static asset candidates and does not send HTTP requests.",
    }
    return profile, summary


def load_target_profile(profile_path: str | None) -> dict[str, Any]:
    path = resolve_repo_path(profile_path or DEFAULT_PROFILE_PATH)
    if path.exists():
        return normalize_target_profile(json.loads(read_text(path)), profile_path=path)
    return normalize_target_profile(default_target_profile(), profile_path=path)


def profile_display_name(profile: dict[str, Any] | None) -> str:
    if not profile:
        return "Target"
    return str(profile.get("display_name") or profile.get("name") or "Target")


def profile_summary(profile: dict[str, Any] | None) -> dict[str, Any]:
    if not profile:
        return {}
    summary = {
        "schema_version": profile.get("schema_version"),
        "name": profile.get("name"),
        "display_name": profile.get("display_name"),
        "assessment_mode": assessment_mode(profile),
        "target_type": profile.get("target_type"),
        "frameworks": profile.get("frameworks", []),
        "strategy_sets": profile.get("strategy_sets", []),
        "profile_path": profile.get("_profile_path"),
        "loaded_from": profile.get("_profile_loaded_from"),
    }
    if is_blackbox_asset_candidate_profile(profile):
        summary["asset_candidate_profile"] = True
    return summary


def resolve_target(args: argparse.Namespace, profile: dict[str, Any]) -> str:
    return str(args.target or profile.get("default_target") or DEFAULT_TARGET).rstrip("/")


def resolve_source_root(args: argparse.Namespace, profile: dict[str, Any]) -> Path:
    source_root = args.source_root or profile.get("default_source_root") or str(DEFAULT_SOURCE_ROOT)
    return resolve_repo_path(source_root)


def resolve_run_context(args: argparse.Namespace) -> tuple[dict[str, Any], Path, str, Path]:
    profile = load_target_profile(args.profile)
    artifact_dir = Path(args.artifact_dir).resolve()
    target = resolve_target(args, profile)
    source_root = resolve_source_root(args, profile)
    return profile, artifact_dir, target, source_root


def source_ref_to_path(source_root: Path, ref: str) -> Path:
    raw = str(ref)
    path = Path(raw)
    if path.is_absolute():
        return path
    if raw == source_root.name or raw.startswith(f"{source_root.name}/"):
        return (ROOT / raw).resolve()
    return (source_root / raw).resolve()


def source_ref_for_artifact(source_root: Path, ref: str) -> str:
    path = source_ref_to_path(source_root, ref)
    try:
        return str(path.relative_to(ROOT))
    except ValueError:
        return str(path)


def write_target_profile_artifact(
    artifact_dir: Path,
    profile: dict[str, Any],
    target: str,
    source_root: Path,
) -> dict[str, Any]:
    doc = public_profile(profile)
    declared_clusters = json_clone(doc.get("clusters", []))
    clusters = build_clusters(profile, source_root)
    doc["generated_at"] = utc_now()
    doc["status"] = "loaded"
    doc["profile_path"] = profile.get("_profile_path")
    doc["loaded_from"] = profile.get("_profile_loaded_from")
    doc["declared_clusters"] = declared_clusters
    doc["effective"] = {
        "target": target,
        "source_root": str(source_root),
        "artifact_dir": str(artifact_dir),
        "enabled_strategy_sets": sorted(enabled_strategy_set_ids(profile)),
        "strategy_registry": STRATEGY_REGISTRY_ARTIFACT,
    }
    doc["clusters"] = clusters["clusters"]
    write_json(artifact_dir / TARGET_PROFILE_ARTIFACT, doc)
    write_json(artifact_dir / STRATEGY_REGISTRY_ARTIFACT, build_strategy_registry_artifact(profile, clusters))
    write_json(artifact_dir / PROFILE_VALIDATION_ARTIFACT, build_profile_validation_artifact(profile, clusters, source_root))
    write_json(
        artifact_dir / "config.json",
        {
            "generated_at": utc_now(),
            "tool": "InferForge local",
            "profile": profile_summary(profile),
            "target_profile": TARGET_PROFILE_ARTIFACT,
            "strategy_registry": STRATEGY_REGISTRY_ARTIFACT,
            "enabled_strategy_sets": sorted(enabled_strategy_set_ids(profile)),
            "target": target,
            "source_root": str(source_root),
            "artifact_dir": str(artifact_dir),
            "safety": "Run context metadata only. No requests are sent when this artifact is written.",
        },
    )
    return doc


def target_profile_artifact_paths(artifact_dir: Path) -> list[Path]:
    return [
        artifact_dir / TARGET_PROFILE_ARTIFACT,
        artifact_dir / STRATEGY_REGISTRY_ARTIFACT,
        artifact_dir / PROFILE_VALIDATION_ARTIFACT,
        artifact_dir / "config.json",
    ]


def redact_text(value: str | None, *, max_chars: int = 500) -> str | None:
    if value is None:
        return None
    redacted = SECRET_TEXT_RE.sub(lambda match: f"{match.group(1) or match.group(2)}[redacted]", value)
    if len(redacted) > max_chars:
        return redacted[:max_chars] + "...[truncated]"
    return redacted


def kib_to_mib(value: int | None) -> float | None:
    if value is None:
        return None
    return round(value / 1024, 1)


def numeric_resource_value(value: Any) -> float | None:
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def build_resource_budget(status: str, warnings: list[str], memory: dict[str, Any]) -> dict[str, Any]:
    mem_available_mib = numeric_resource_value(memory.get("mem_available_mib"))
    swap_used_pct = numeric_resource_value(memory.get("swap_used_pct"))
    severe_memory_pressure = bool(
        status != "healthy"
        and (
            (mem_available_mib is not None and mem_available_mib < DEFAULT_RESOURCE_CRITICAL_AVAILABLE_MIB)
            or (swap_used_pct is not None and swap_used_pct >= DEFAULT_RESOURCE_CRITICAL_SWAP_USED_PCT)
        )
    )
    if status == "healthy":
        mode = "normal"
        offline_limit = 8
        burp_count_limit = DEFAULT_BURP_SYNC_COUNT
        active_target_traffic = "allowed-after-resource-check"
        browser_automation = "allowed-after-resource-check"
        recommendations = [
            "Run resource-snapshot --strict immediately before active target traffic.",
            "Keep Burp history reads bounded and avoid raw history persistence unless explicitly debugging.",
        ]
    elif severe_memory_pressure:
        mode = "critical"
        offline_limit = DEFAULT_RESOURCE_CRITICAL_OFFLINE_COMMAND_LIMIT
        burp_count_limit = DEFAULT_RESOURCE_CRITICAL_BURP_SYNC_COUNT
        active_target_traffic = "blocked"
        browser_automation = "blocked"
        recommendations = [
            "Do not start the target server, browser automation, Burp Scanner, Intruder, broad crawling, or active probes.",
            "Run only short offline planning, artifact-health, and source-review commands until swap pressure clears.",
            "If Burp history must be read after explicit approval, use the capped effective count recorded in burp-sync artifacts.",
        ]
    else:
        mode = "degraded"
        offline_limit = DEFAULT_RESOURCE_DEGRADED_OFFLINE_COMMAND_LIMIT
        burp_count_limit = DEFAULT_RESOURCE_WARNING_BURP_SYNC_COUNT
        active_target_traffic = "blocked"
        browser_automation = "blocked"
        recommendations = [
            "Prefer no-write offline review commands and avoid starting new long-running local services.",
            "Run active target traffic only after resource-snapshot --strict is healthy.",
            "If a resource warning is explicitly accepted, keep Burp history and probe limits at the resource-budget caps.",
        ]

    return {
        "mode": mode,
        "warnings": warnings,
        "offline_command_preview_limit": offline_limit,
        "burp_history_count_limit": burp_count_limit,
        "active_target_traffic": active_target_traffic,
        "browser_automation": browser_automation,
        "allow_raw_burp_history": False,
        "allow_scanner_or_intruder": False,
        "recommendations": recommendations,
    }


def read_proc_meminfo() -> dict[str, int]:
    meminfo_path = Path("/proc/meminfo")
    meminfo: dict[str, int] = {}
    try:
        lines = meminfo_path.read_text(encoding="utf-8").splitlines()
    except OSError:
        return meminfo
    for line in lines:
        key, sep, rest = line.partition(":")
        if not sep:
            continue
        parts = rest.strip().split()
        if not parts or not parts[0].isdigit():
            continue
        meminfo[key] = int(parts[0])
    return meminfo


def proc_cmdline_preview(pid: int, *, max_chars: int = 180) -> str | None:
    try:
        raw = (Path("/proc") / str(pid) / "cmdline").read_bytes()[:4096]
    except OSError:
        return None
    parts = [
        part.decode("utf-8", errors="replace")
        for part in raw.split(b"\0")
        if part
    ]
    if not parts:
        return None
    return redact_text(" ".join(parts), max_chars=max_chars)


def parse_proc_status(pid: int) -> dict[str, Any] | None:
    try:
        lines = (Path("/proc") / str(pid) / "status").read_text(encoding="utf-8").splitlines()
    except OSError:
        return None
    parsed: dict[str, Any] = {"pid": pid}
    for line in lines:
        key, sep, rest = line.partition(":")
        if not sep:
            continue
        value = rest.strip()
        if key == "Name":
            parsed["name"] = value
        elif key == "PPid":
            try:
                parsed["ppid"] = int(value)
            except ValueError:
                pass
        elif key == "VmRSS":
            parts = value.split()
            if parts and parts[0].isdigit():
                parsed["rss_kib"] = int(parts[0])
    if "rss_kib" not in parsed:
        return None
    parsed["rss_mib"] = kib_to_mib(int(parsed["rss_kib"]))
    preview = proc_cmdline_preview(pid)
    if preview:
        parsed["command_preview"] = preview
    return parsed


def top_rss_processes(limit: int) -> list[dict[str, Any]]:
    proc_root = Path("/proc")
    processes: list[dict[str, Any]] = []
    try:
        entries = list(proc_root.iterdir())
    except OSError:
        return processes
    for entry in entries:
        if not entry.name.isdigit():
            continue
        parsed = parse_proc_status(int(entry.name))
        if parsed is not None:
            processes.append(parsed)
    processes.sort(key=lambda item: int(item.get("rss_kib") or 0), reverse=True)
    return processes[:limit]


def resource_release_candidates(processes: list[dict[str, Any]]) -> list[dict[str, Any]]:
    candidates = []
    for process in processes:
        rss_mib = numeric_resource_value(process.get("rss_mib"))
        if rss_mib is None or rss_mib < 256:
            continue
        name = str(process.get("name") or "")
        command = str(process.get("command_preview") or "")
        lowered = f"{name} {command}".lower()
        if "codex" in lowered or ".vscode-server" in lowered:
            continue
        if "burpsuite" in lowered or ("java" in name.lower() and "burp" in lowered):
            candidate_type = "burp-gui"
            recommendation = "Close idle Burp GUI before offline iteration; restart it only for an approved bounded observation."
        elif any(token in lowered for token in ["firefox", "chrome", "chromium", "playwright"]):
            candidate_type = "browser"
            recommendation = "Close idle browsers or browser automation before active target work."
        elif "--port 3100" in lowered or "--port 2455" in lowered or "next dev" in lowered:
            candidate_type = "local-service"
            recommendation = "Review whether this local service is still needed before continuing memory-sensitive work."
        else:
            continue
        candidates.append(
            {
                "pid": process.get("pid"),
                "name": name,
                "rss_mib": process.get("rss_mib"),
                "type": candidate_type,
                "recommendation": recommendation,
                "safe_action": "Prefer graceful application shutdown; do not kill unknown user/session processes automatically.",
            }
        )
    return candidates


def listening_tcp_ports() -> list[int]:
    ports: set[int] = set()
    for path in [Path("/proc/net/tcp"), Path("/proc/net/tcp6")]:
        try:
            lines = path.read_text(encoding="utf-8").splitlines()[1:]
        except OSError:
            continue
        for line in lines:
            parts = line.split()
            if len(parts) < 4 or parts[3] != "0A":
                continue
            local_address = parts[1]
            if ":" not in local_address:
                continue
            _address, port_hex = local_address.rsplit(":", 1)
            try:
                ports.add(int(port_hex, 16))
            except ValueError:
                continue
    return sorted(ports)


def build_resource_snapshot(
    *,
    max_processes: int,
    watch_ports: list[int],
    warn_available_mib: int,
    warn_swap_used_mib: int,
) -> dict[str, Any]:
    meminfo = read_proc_meminfo()
    mem_total = meminfo.get("MemTotal")
    mem_available = meminfo.get("MemAvailable", meminfo.get("MemFree"))
    swap_total = meminfo.get("SwapTotal")
    swap_free = meminfo.get("SwapFree")
    swap_used = None
    if swap_total is not None and swap_free is not None:
        swap_used = max(0, swap_total - swap_free)
    warnings: list[str] = []
    if mem_available is not None and mem_available < warn_available_mib * 1024:
        warnings.append("available-memory-below-threshold")
    if swap_used is not None and swap_used > warn_swap_used_mib * 1024:
        warnings.append("swap-usage-above-threshold")

    memory = {
        "mem_total_mib": kib_to_mib(mem_total),
        "mem_available_mib": kib_to_mib(mem_available),
        "mem_available_pct": (
            round((mem_available / mem_total) * 100, 1)
            if mem_total and mem_available is not None
            else None
        ),
        "swap_total_mib": kib_to_mib(swap_total),
        "swap_used_mib": kib_to_mib(swap_used),
        "swap_used_pct": (
            round((swap_used / swap_total) * 100, 1)
            if swap_total and swap_used is not None
            else None
        ),
    }
    status = "warning" if warnings else "healthy"
    listening_ports = set(listening_tcp_ports())
    watched_ports = {
        str(port): {"listening": port in listening_ports}
        for port in sorted(set(watch_ports))
    }
    top_processes = top_rss_processes(max(max_processes, 8))
    resource_budget = build_resource_budget(status, warnings, memory)
    return {
        "generated_at": utc_now(),
        "status": status,
        "warnings": warnings,
        "thresholds": {
            "warn_available_mib": warn_available_mib,
            "warn_swap_used_mib": warn_swap_used_mib,
            "critical_available_mib": DEFAULT_RESOURCE_CRITICAL_AVAILABLE_MIB,
            "critical_swap_used_pct": DEFAULT_RESOURCE_CRITICAL_SWAP_USED_PCT,
        },
        "memory": memory,
        "resource_budget": resource_budget,
        "watched_ports": watched_ports,
        "top_rss_processes": top_processes[:max_processes],
        "release_candidates": resource_release_candidates(top_processes),
        "safety": (
            "Local /proc snapshot only. Command lines are shortened and secret-like "
            "tokens are redacted; no network requests or target probes are performed."
        ),
    }


def build_default_resource_snapshot(*, max_processes: int = 8) -> dict[str, Any]:
    return build_resource_snapshot(
        max_processes=max_processes,
        watch_ports=DEFAULT_RESOURCE_WATCH_PORTS,
        warn_available_mib=DEFAULT_RESOURCE_WARN_AVAILABLE_MIB,
        warn_swap_used_mib=DEFAULT_RESOURCE_WARN_SWAP_USED_MIB,
    )


def resource_gate_warnings_text(resource_snapshot: dict[str, Any] | None) -> str:
    warnings = (resource_snapshot or {}).get("warnings", []) if isinstance(resource_snapshot, dict) else []
    return ",".join(str(item) for item in warnings) if warnings else "none"


def resource_gate_blocked_artifact(
    *,
    command: str,
    target: str,
    profile: dict[str, Any] | None,
    resource_snapshot: dict[str, Any],
    blocked_actions: list[str],
    allow_flag: str = "--allow-resource-warning",
) -> dict[str, Any]:
    return {
        "generated_at": utc_now(),
        "status": "blocked-resource-gate",
        "command": command,
        "target": target,
        "profile": profile_summary(profile),
        "resource_preflight": validation_resource_preflight_summary(resource_snapshot),
        "resource_snapshot": resource_snapshot,
        "blocked_actions": blocked_actions,
        "next_step": (
            "Free memory or rerun after explicit review with "
            f"{allow_flag} and the smallest practical target/probe/history limits."
        ),
        "safety": [
            "No active target probes, Burp history reads, scanner actions, fuzzing, wallet signing, or transaction submission were run.",
            "The command stopped before long-running or memory-sensitive work because the local memory/swap gate is warning.",
        ],
    }


def resource_budget_for_snapshot(resource_snapshot: dict[str, Any] | None) -> dict[str, Any]:
    if not isinstance(resource_snapshot, dict) or not resource_snapshot:
        return {}
    budget = resource_snapshot.get("resource_budget")
    if isinstance(budget, dict) and budget:
        return budget
    status = artifact_summary_status(resource_snapshot)
    if status not in {"healthy", "warning"}:
        return {}
    return build_resource_budget(
        status,
        [str(item) for item in resource_snapshot.get("warnings", []) or []],
        resource_snapshot.get("memory", {}) if isinstance(resource_snapshot.get("memory"), dict) else {},
    )


def effective_burp_history_count(
    requested_count: int,
    resource_snapshot: dict[str, Any] | None,
) -> tuple[int, dict[str, Any] | None]:
    requested = max(1, int(requested_count))
    resource_status = artifact_summary_status(resource_snapshot)
    if resource_status == "healthy":
        return requested, None
    budget = resource_budget_for_snapshot(resource_snapshot)
    raw_limit = budget.get("burp_history_count_limit") if budget else None
    try:
        limit = max(1, int(raw_limit))
    except (TypeError, ValueError):
        limit = DEFAULT_RESOURCE_WARNING_BURP_SYNC_COUNT
    effective = min(requested, limit)
    if effective == requested:
        return effective, None
    return effective, {
        "reason": "resource-budget-cap",
        "resource_status": resource_status,
        "budget_mode": budget.get("mode") if budget else resource_status,
        "requested_count": requested,
        "effective_count": effective,
        "limit": limit,
    }


def normalize_scope_host(host: Any) -> str:
    return str(host or "").lower().strip().strip(".")


def scope_policy_seen_hosts(asset_candidates_doc: dict[str, Any] | None) -> dict[str, dict[str, Any]]:
    seen: dict[str, dict[str, Any]] = {}

    def item_for(host: Any) -> dict[str, Any] | None:
        normalized = normalize_scope_host(host)
        if not normalized:
            return None
        return seen.setdefault(
            normalized,
            {
                "host": normalized,
                "sources": {},
                "roles": {},
                "schemes": {},
                "triage_classes": {},
                "sample_paths": [],
            },
        )

    doc = asset_candidates_doc if isinstance(asset_candidates_doc, dict) else {}
    for candidate in doc.get("candidates", []) or []:
        if not isinstance(candidate, dict):
            continue
        item = item_for(candidate.get("host"))
        if item is None:
            continue
        increment_count(item["sources"], "asset-candidate")
        triage_class = (candidate.get("triage", {}) or {}).get("class") if isinstance(candidate.get("triage"), dict) else None
        if triage_class:
            increment_count(item["triage_classes"], str(triage_class))
        path = str(candidate.get("path") or "")
        if path and len(item["sample_paths"]) < 4 and path not in item["sample_paths"]:
            item["sample_paths"].append(path)

    external_scripts = doc.get("external_scripts", {}) if isinstance(doc.get("external_scripts"), dict) else {}
    for host, count in (external_scripts.get("host_counts", {}) or {}).items():
        item = item_for(host)
        if item is None:
            continue
        item["sources"]["external-script"] = int(count or 0)
    for sample in external_scripts.get("samples", []) or []:
        if not isinstance(sample, dict):
            continue
        item = item_for(sample.get("host"))
        if item is None:
            continue
        path = str(sample.get("path") or "")
        if path and len(item["sample_paths"]) < 4 and path not in item["sample_paths"]:
            item["sample_paths"].append(path)

    config_hosts = doc.get("config_hosts", {}) if isinstance(doc.get("config_hosts"), dict) else {}
    for host_item in config_hosts.get("hosts", []) or []:
        if not isinstance(host_item, dict):
            continue
        item = item_for(host_item.get("host"))
        if item is None:
            continue
        item["sources"]["runtime-config"] = int(host_item.get("count") or 0)
        for role, count in (host_item.get("roles", {}) or {}).items():
            item["roles"][str(role)] = int(count or 0)
        for scheme, count in (host_item.get("schemes", {}) or {}).items():
            item["schemes"][str(scheme)] = int(count or 0)
        triage_class = (host_item.get("triage", {}) or {}).get("class") if isinstance(host_item.get("triage"), dict) else None
        if triage_class:
            increment_count(item["triage_classes"], str(triage_class))
        for sample in host_item.get("samples", []) or []:
            if not isinstance(sample, dict):
                continue
            path = str(sample.get("path") or "")
            if path and len(item["sample_paths"]) < 4 and path not in item["sample_paths"]:
                item["sample_paths"].append(path)
    return seen


def build_scope_policy(
    *,
    target: str,
    allowed_hosts: set[str],
    asset_candidates_doc: dict[str, Any] | None,
    deny_unlisted_hosts: bool,
    source_url: str | None = None,
    source_label: str | None = None,
) -> dict[str, Any]:
    target_host = normalize_scope_host(urllib.parse.urlparse(target).netloc)
    normalized_allowed = {normalize_scope_host(host) for host in allowed_hosts if normalize_scope_host(host)}
    if target_host:
        normalized_allowed.add(target_host)
    seen_hosts = scope_policy_seen_hosts(asset_candidates_doc)
    for host in normalized_allowed:
        seen_hosts.setdefault(
            host,
            {
                "host": host,
                "sources": {"explicit-allowlist": 1},
                "roles": {},
                "schemes": {},
                "triage_classes": {},
                "sample_paths": [],
            },
        )

    decisions = []
    decision_counts: dict[str, int] = {}
    source_counts: dict[str, int] = {}
    for item in sorted(seen_hosts.values(), key=lambda row: row["host"]):
        host = str(item["host"])
        if host in normalized_allowed:
            decision = "in-scope-explicit-host"
            reason = "Host is present in the explicit scope host allowlist for this policy."
            safe_next_step = "Use only the existing low-volume reviewed workflows for this host."
        elif deny_unlisted_hosts:
            decision = "out-of-scope-by-default"
            reason = "Host is not present in the explicit scope host allowlist; deny-by-default is enabled."
            safe_next_step = "Do not request this host from automation unless the bounty scope is updated and the policy is regenerated."
        else:
            decision = "needs-scope-review"
            reason = "Host is not present in the explicit scope host allowlist and deny-by-default is disabled."
            safe_next_step = "Confirm bounty scope before using this host as a target."
        increment_count(decision_counts, decision)
        for source, count in item.get("sources", {}).items():
            source_counts[str(source)] = source_counts.get(str(source), 0) + int(count or 0)
        decisions.append(
            {
                "host": host,
                "decision": decision,
                "reason": reason,
                "safe_next_step": safe_next_step,
                "sources": dict(sorted((item.get("sources") or {}).items())),
                "roles": dict(sorted((item.get("roles") or {}).items())),
                "schemes": dict(sorted((item.get("schemes") or {}).items())),
                "triage_classes": dict(sorted((item.get("triage_classes") or {}).items())),
                "sample_paths": item.get("sample_paths", [])[:4],
            }
        )

    unresolved_hosts = [item["host"] for item in decisions if item.get("decision") == "needs-scope-review"]
    return {
        "generated_at": utc_now(),
        "status": "needs-scope-review" if unresolved_hosts else "complete",
        "target": target,
        "source": {
            "label": source_label or "explicit-scope-host-policy",
            "url": source_url,
        },
        "policy": {
            "allowed_hosts": sorted(normalized_allowed),
            "deny_unlisted_hosts": bool(deny_unlisted_hosts),
        },
        "summary": {
            "host_count": len(decisions),
            "decision_counts": dict(sorted(decision_counts.items())),
            "source_counts": dict(sorted(source_counts.items())),
            "unresolved_host_count": len(unresolved_hosts),
        },
        "unresolved_hosts": unresolved_hosts,
        "decisions": decisions,
        "safety": (
            "Scope policy is an allowlist/deny-by-default planning artifact. "
            "It does not request hosts and does not prove vulnerability impact."
        ),
    }


def scope_policy_decision_map(scope_policy: dict[str, Any] | None) -> dict[str, str]:
    if not isinstance(scope_policy, dict):
        return {}
    return {
        normalize_scope_host(item.get("host")): str(item.get("decision") or "")
        for item in scope_policy.get("decisions", []) or []
        if isinstance(item, dict) and normalize_scope_host(item.get("host"))
    }


def scope_policy_unresolved_hosts(scope_policy: dict[str, Any] | None, hosts: list[str]) -> list[str]:
    decisions = scope_policy_decision_map(scope_policy)
    unresolved = []
    for host in sorted({normalize_scope_host(item) for item in hosts if normalize_scope_host(item)}):
        decision = decisions.get(host)
        if decision not in {"in-scope-explicit-host", "out-of-scope-by-default"}:
            unresolved.append(host)
    return unresolved


def scope_policy_decision_counts_for_hosts(scope_policy: dict[str, Any] | None, hosts: list[str]) -> dict[str, int]:
    decisions = scope_policy_decision_map(scope_policy)
    counts: dict[str, int] = {}
    for host in sorted({normalize_scope_host(item) for item in hosts if normalize_scope_host(item)}):
        increment_count(counts, decisions.get(host) or "missing-policy-decision")
    return dict(sorted(counts.items()))


def websocket_candidate_rows(asset_candidates_doc: dict[str, Any] | None) -> list[dict[str, Any]]:
    doc = asset_candidates_doc if isinstance(asset_candidates_doc, dict) else {}
    return [
        item
        for item in doc.get("candidates", []) or []
        if isinstance(item, dict)
        and ((item.get("triage", {}) or {}).get("class") == "websocket-handshake-review")
    ]


def websocket_candidate_url(candidate: dict[str, Any], target: str) -> str:
    target_scheme = urllib.parse.urlparse(target).scheme
    scheme = "wss" if target_scheme == "https" else "ws"
    host = normalize_scope_host(candidate.get("host"))
    path = str(candidate.get("path") or "/")
    if not path.startswith("/"):
        path = "/" + path
    return urllib.parse.urlunparse((scheme, host, path, "", "", ""))


def build_websocket_candidate_review(
    *,
    target: str,
    asset_candidates_doc: dict[str, Any] | None,
    scope_policy: dict[str, Any] | None,
    baseline_results: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    scope_decisions = scope_policy_decision_map(scope_policy)
    baseline_by_id = {
        str(item.get("candidate_id") or ""): item
        for item in baseline_results or []
        if isinstance(item, dict)
    }
    candidates = []
    decision_counts: dict[str, int] = {}
    baseline_status_counts: dict[str, int] = {}
    for candidate in websocket_candidate_rows(asset_candidates_doc):
        candidate_id = str(candidate.get("id") or "")
        host = normalize_scope_host(candidate.get("host"))
        scope_decision = scope_decisions.get(host) or "missing-policy-decision"
        path_problem = concrete_local_path_problem(candidate.get("path") or "/")
        if scope_decision == "in-scope-explicit-host" and not path_problem:
            decision = "handshake-baseline-ready"
            safe_next_step = "At most one handshake-only connection may be used for baseline evidence; do not send frames."
        elif scope_decision == "out-of-scope-by-default":
            decision = "out-of-scope-by-default"
            safe_next_step = "Do not request this WebSocket host from automation."
        elif path_problem:
            decision = "blocked-unsafe-path"
            safe_next_step = f"Do not connect until the path is concrete and safe: {path_problem}."
        else:
            decision = "needs-scope-review"
            safe_next_step = "Confirm explicit bounty scope before any WebSocket handshake."
        baseline = baseline_by_id.get(candidate_id)
        if baseline:
            increment_count(baseline_status_counts, str(baseline.get("status") or "unknown"))
        increment_count(decision_counts, decision)
        candidates.append(
            {
                "id": candidate_id,
                "host": host,
                "path": candidate.get("path") or "/",
                "url": websocket_candidate_url(candidate, target),
                "scope_decision": scope_decision,
                "decision": decision,
                "safe_next_step": safe_next_step,
                "triage": candidate.get("triage", {}),
                "source_refs": candidate.get("sources", [])[:3],
                "baseline": baseline,
            }
        )

    unresolved = [
        item["id"]
        for item in candidates
        if item.get("decision") not in {"handshake-baseline-ready", "out-of-scope-by-default"}
    ]
    ready_count = sum(1 for item in candidates if item.get("decision") == "handshake-baseline-ready")
    baseline_expected = [
        item
        for item in candidates
        if isinstance(item.get("baseline"), dict) and item["baseline"].get("expected")
    ]
    status = "no-websocket-candidates"
    if candidates:
        if unresolved:
            status = "needs-human-review"
        elif ready_count and len(baseline_expected) == ready_count:
            status = "baseline-complete"
        elif ready_count:
            status = "ready-for-handshake-baseline"
        else:
            status = "complete"
    return {
        "generated_at": utc_now(),
        "status": status,
        "target": target,
        "summary": {
            "candidate_count": len(candidates),
            "ready_for_handshake_baseline": ready_count,
            "unresolved_count": len(unresolved),
            "decision_counts": dict(sorted(decision_counts.items())),
            "baseline_status_counts": dict(sorted(baseline_status_counts.items())),
        },
        "candidates": candidates,
        "safety": (
            "WebSocket candidate review only. Handshake baselines, when requested, perform one HTTP Upgrade "
            "attempt per in-scope candidate and send no WebSocket frames, subscriptions, wallet payloads, or trade messages."
        ),
    }


def lead_priority_from_values(*values: Any) -> str:
    order = {"critical": 0, "high": 1, "medium": 2, "low": 3, "info": 4}
    best = "info"
    best_rank = order[best]
    for value in values:
        text = str(value or "").lower()
        if text in order and order[text] < best_rank:
            best = text
            best_rank = order[text]
    return best


def lead_status_from_scope(scope_decision: str, *, default: str = "needs-review") -> str:
    if scope_decision == "out-of-scope-by-default":
        return "out-of-scope-by-default"
    if scope_decision in {"", "missing-policy-decision", "needs-scope-review"}:
        return "needs-scope-review"
    return default


LEAD_TERMINAL_STATUSES = {
    "out-of-scope-by-default",
    "no-takeover-signal",
    "promoted-to-asset-profile",
    "scope-covered-reference",
    "websocket-baseline-complete",
}

LEAD_PRIORITY_ORDER = {"critical": 0, "high": 1, "medium": 2, "low": 3, "info": 4}


def is_terminal_lead_status(status: Any) -> bool:
    return str(status or "") in LEAD_TERMINAL_STATUSES


def lead_sort_key(item: dict[str, Any]) -> tuple[Any, ...]:
    return (
        1 if is_terminal_lead_status(item.get("status")) else 0,
        0 if str(item.get("scope_decision") or "") == "in-scope-explicit-host" else 1,
        LEAD_PRIORITY_ORDER.get(str(item.get("priority") or "info"), 9),
        str(item.get("status") or ""),
        str(item.get("type") or ""),
        str(item.get("host") or ""),
        str(item.get("path") or ""),
        str(item.get("artifact_dir") or ""),
    )


def build_lead_portfolio(
    *,
    target: str,
    asset_candidates_doc: dict[str, Any] | None,
    scope_policy: dict[str, Any] | None,
    asset_profile: dict[str, Any] | None = None,
    websocket_candidate_review: dict[str, Any] | None = None,
    host_takeover_baseline: dict[str, Any] | None = None,
) -> dict[str, Any]:
    doc = asset_candidates_doc if isinstance(asset_candidates_doc, dict) else {}
    scope_decisions = scope_policy_decision_map(scope_policy)
    promoted_candidate_ids = {
        str(candidate_id)
        for cluster in (asset_profile or {}).get("clusters", []) or []
        if isinstance(cluster, dict)
        for candidate_id in (cluster.get("discovery", {}) or {}).get("source_candidate_ids", []) or []
    }
    ws_review_by_id = {
        str(item.get("id") or ""): item
        for item in (websocket_candidate_review or {}).get("candidates", []) or []
        if isinstance(item, dict)
    }
    takeover_by_host = {
        normalize_scope_host(item.get("host")): item
        for item in (host_takeover_baseline or {}).get("hosts", []) or []
        if isinstance(item, dict) and normalize_scope_host(item.get("host"))
    }
    leads: list[dict[str, Any]] = []

    def add_lead(lead: dict[str, Any]) -> None:
        lead["id"] = str(lead.get("id") or f"lead-{len(leads) + 1}")
        lead["evidence_refs"] = compact_source_refs(lead.get("evidence_refs", []) or [])
        lead["safety"] = str(
            lead.get("safety")
            or "Lead portfolio is passive artifact triage only. Do not report or probe without explicit evidence and scope."
        )
        leads.append(lead)

    for candidate in doc.get("candidates", []) or []:
        if not isinstance(candidate, dict):
            continue
        candidate_id = str(candidate.get("id") or safe_probe_id(f"{candidate.get('host')}-{candidate.get('path')}"))
        host = normalize_scope_host(candidate.get("host"))
        triage = candidate.get("triage") if isinstance(candidate.get("triage"), dict) else {}
        triage_class = str(triage.get("class") or "unclassified")
        scope_decision = scope_decisions.get(host) or "missing-policy-decision"
        if candidate_id in promoted_candidate_ids:
            status = "promoted-to-asset-profile"
            next_step = "Use generated asset-profile probes and Burp observation evidence; keep reportability gated on concrete impact."
        elif triage_class == "websocket-handshake-review":
            ws_review = ws_review_by_id.get(candidate_id, {})
            decision = str(ws_review.get("decision") or "")
            if isinstance(ws_review.get("baseline"), dict):
                status = "websocket-baseline-complete"
                next_step = "Treat handshake result as coverage only; do not send frames without a reviewed message-level plan."
            elif decision == "handshake-baseline-ready":
                status = "ready-for-handshake-baseline"
                next_step = "Run at most one handshake-only baseline if scope and resource budget remain acceptable."
            else:
                status = lead_status_from_scope(scope_decision, default="manual-websocket-review")
                next_step = "Confirm scope and message semantics before any WebSocket handshake or frame."
        elif triage_class == "passive-page-route-review":
            status = lead_status_from_scope(scope_decision, default="ready-for-reviewed-asset-profile")
            next_step = "Promote only reviewed low-risk page routes into an asset profile; prefer HEAD observations."
        else:
            status = lead_status_from_scope(scope_decision, default="manual-review")
            next_step = "Review authentication, mutation risk, and reportability gate before any request."
        add_lead(
            {
                "id": f"asset-candidate:{candidate_id}",
                "type": "asset-candidate",
                "status": status,
                "priority": lead_priority_from_values(triage.get("priority"), triage.get("risk")),
                "host": host,
                "path": candidate.get("path"),
                "method_hint": candidate.get("method_hint"),
                "scope_decision": scope_decision,
                "triage_class": triage_class,
                "risk": triage.get("risk"),
                "reportability_gate": triage.get("reportability_gate") or "Lead only until concrete in-scope impact is demonstrated.",
                "next_step": next_step,
                "evidence_refs": [BLACKBOX_ASSET_CANDIDATES_ARTIFACT, SCOPE_POLICY_ARTIFACT],
                "safety": "Static asset candidate triage only. Candidate endpoints are not requested by lead-portfolio.",
            }
        )

    config_hosts = doc.get("config_hosts", {}) if isinstance(doc.get("config_hosts"), dict) else {}
    for item in config_hosts.get("hosts", []) or []:
        if not isinstance(item, dict):
            continue
        host = normalize_scope_host(item.get("host"))
        triage = item.get("triage") if isinstance(item.get("triage"), dict) else {}
        scope_decision = scope_decisions.get(host) or "missing-policy-decision"
        triage_class = str(triage.get("class") or "")
        status = lead_status_from_scope(scope_decision, default="runtime-host-review")
        if scope_decision == "in-scope-explicit-host" and triage_class == "explicitly-allowed-runtime-host":
            status = "scope-covered-reference"
        add_lead(
            {
                "id": f"runtime-host:{host}",
                "type": "runtime-config-host",
                "status": status,
                "priority": lead_priority_from_values(triage.get("priority")),
                "host": host,
                "scope_decision": scope_decision,
                "roles": item.get("roles", {}),
                "schemes": item.get("schemes", {}),
                "triage_class": triage_class,
                "impact_hypotheses": triage.get("impact_hypotheses", []),
                "reportability_gate": triage.get("reportability_gate") or "A configuration reference is not reportable without a concrete PoC.",
                "next_step": (
                    "Do not request this host from automation unless scope changes."
                    if scope_decision == "out-of-scope-by-default"
                    else (
                        "No action from the configuration reference alone; use host-specific runs for concrete evidence."
                        if status == "scope-covered-reference"
                        else "Confirm scope and concrete user, funds, order, sensitive-data, or takeover impact before probing."
                    )
                ),
                "sample_paths": item.get("samples", [])[:2],
                "evidence_refs": [BLACKBOX_ASSET_CANDIDATES_ARTIFACT, SCOPE_POLICY_ARTIFACT],
                "safety": "Runtime host mapping is passive. lead-portfolio does not request referenced hosts.",
            }
        )

    external_scripts = doc.get("external_scripts", {}) if isinstance(doc.get("external_scripts"), dict) else {}
    for host, count in (external_scripts.get("host_counts", {}) or {}).items():
        normalized_host = normalize_scope_host(host)
        scope_decision = scope_decisions.get(normalized_host) or "missing-policy-decision"
        add_lead(
            {
                "id": f"external-script-host:{normalized_host}",
                "type": "external-script-host",
                "status": lead_status_from_scope(scope_decision, default="external-script-review"),
                "priority": "low",
                "host": normalized_host,
                "scope_decision": scope_decision,
                "script_url_count": int(count or 0),
                "reportability_gate": "External script reference is not reportable without confirmed scope and persistent target-app content impact.",
                "next_step": (
                    "Do not fetch this host from automation unless explicit scope changes."
                    if scope_decision == "out-of-scope-by-default"
                    else "Confirm whether the script host is an in-scope static asset source before fetching."
                ),
                "evidence_refs": [BLACKBOX_ASSET_CANDIDATES_ARTIFACT, SCOPE_POLICY_ARTIFACT],
                "safety": "External script host lead only. lead-portfolio does not fetch external scripts.",
            }
        )

    for host, item in takeover_by_host.items():
        status = str(item.get("status") or "unknown")
        add_lead(
            {
                "id": f"takeover-baseline:{host}",
                "type": "host-takeover-baseline",
                "status": status,
                "priority": "high" if status != "no-takeover-signal" else "info",
                "host": host,
                "scope_decision": scope_decisions.get(host) or "missing-policy-decision",
                "provider_hints": item.get("provider_hints", []),
                "fingerprints": item.get("fingerprints", []),
                "reportability_gate": "Report only with a confirmed takeover signal on an in-scope host.",
                "next_step": "No action if no takeover signal; review provider hints only when fingerprints indicate dangling resources.",
                "evidence_refs": [HOST_TAKEOVER_BASELINE_ARTIFACT, SCOPE_POLICY_ARTIFACT],
                "safety": "Host takeover baseline evidence only. Do not claim or modify third-party resources.",
            }
        )

    leads.sort(key=lead_sort_key)
    status_counts: dict[str, int] = {}
    priority_counts: dict[str, int] = {}
    type_counts: dict[str, int] = {}
    scope_counts: dict[str, int] = {}
    actionable_count = 0
    for lead in leads:
        status = str(lead.get("status") or "unknown")
        increment_count(status_counts, status)
        increment_count(priority_counts, str(lead.get("priority") or "info"))
        increment_count(type_counts, str(lead.get("type") or "unknown"))
        increment_count(scope_counts, str(lead.get("scope_decision") or "missing-policy-decision"))
        if not is_terminal_lead_status(status):
            actionable_count += 1

    return {
        "generated_at": utc_now(),
        "status": "has-actionable-leads" if actionable_count else ("leads-indexed" if leads else "no-leads"),
        "target": target,
        "summary": {
            "leads": len(leads),
            "actionable_leads": actionable_count,
            "status_counts": dict(sorted(status_counts.items())),
            "priority_counts": dict(sorted(priority_counts.items())),
            "type_counts": dict(sorted(type_counts.items())),
            "scope_decision_counts": dict(sorted(scope_counts.items())),
        },
        "leads": leads,
        "artifact_refs": {
            "asset_candidates": BLACKBOX_ASSET_CANDIDATES_ARTIFACT,
            "scope_policy": SCOPE_POLICY_ARTIFACT,
            "asset_profile": BLACKBOX_ASSET_PROFILE_ARTIFACT,
            "websocket_candidate_review": WEBSOCKET_CANDIDATE_REVIEW_ARTIFACT,
            "host_takeover_baseline": HOST_TAKEOVER_BASELINE_ARTIFACT,
        },
        "safety": (
            "Lead portfolio is passive triage over existing local artifacts. It sends no requests, "
            "does not prove impact, and must not be treated as a reportable finding without a concrete PoC."
        ),
    }


def compact_rollup_lead(lead: dict[str, Any]) -> dict[str, Any]:
    compact: dict[str, Any] = {}
    for field in [
        "id",
        "run_lead_id",
        "artifact_dir",
        "type",
        "status",
        "priority",
        "host",
        "path",
        "method_hint",
        "scope_decision",
        "triage_class",
        "reportability_gate",
        "next_step",
        "source_lead_portfolio",
    ]:
        if lead.get(field) not in (None, "", []):
            compact[field] = lead.get(field)
    refs = compact_source_refs(lead.get("evidence_refs", []) or [])
    if refs:
        compact["evidence_refs"] = refs
    return compact


def build_lead_portfolio_rollup(
    *,
    target: str,
    profile: dict[str, Any] | None,
    artifact_dir: Path,
    check_dirs: list[Path],
) -> dict[str, Any]:
    leads: list[dict[str, Any]] = []
    runs = []
    missing = []
    run_status_counts: dict[str, int] = {}

    for check_dir in check_dirs:
        path = check_dir / LEAD_PORTFOLIO_ARTIFACT
        relative_dir = repo_relative_or_absolute(check_dir)
        if not path.exists():
            missing.append(relative_dir)
            increment_count(run_status_counts, "missing-lead-portfolio")
            runs.append(
                {
                    "artifact_dir": relative_dir,
                    "status": "missing-lead-portfolio",
                    "lead_portfolio": repo_relative_or_absolute(path),
                    "summary": {},
                }
            )
            continue

        doc = load_optional_json(path) or {}
        run_status = str(doc.get("status") or "unknown")
        increment_count(run_status_counts, run_status)
        runs.append(
            {
                "artifact_dir": relative_dir,
                "target": doc.get("target"),
                "status": run_status,
                "lead_portfolio": repo_relative_or_absolute(path),
                "summary": doc.get("summary", {}),
            }
        )
        for index, lead in enumerate(doc.get("leads", []) or [], start=1):
            if not isinstance(lead, dict):
                continue
            row = json_clone(lead)
            original_id = str(row.get("id") or f"lead-{index}")
            row["id"] = f"RUN-{safe_probe_id(relative_dir)}-{original_id}"
            row["run_lead_id"] = original_id
            row["artifact_dir"] = relative_dir
            row["source_lead_portfolio"] = repo_relative_or_absolute(path)
            row["evidence_refs"] = compact_source_refs(
                [
                    f"{relative_dir}/{ref}" if not str(ref).startswith("/") else str(ref)
                    for ref in row.get("evidence_refs", []) or []
                ]
            )
            leads.append(row)

    leads.sort(key=lead_sort_key)
    status_counts: dict[str, int] = {}
    priority_counts: dict[str, int] = {}
    type_counts: dict[str, int] = {}
    scope_counts: dict[str, int] = {}
    source_counts: dict[str, int] = {}
    actionable_count = 0
    for lead in leads:
        status = str(lead.get("status") or "unknown")
        increment_count(status_counts, status)
        increment_count(priority_counts, str(lead.get("priority") or "info"))
        increment_count(type_counts, str(lead.get("type") or "unknown"))
        increment_count(scope_counts, str(lead.get("scope_decision") or "missing-policy-decision"))
        increment_count(source_counts, str(lead.get("artifact_dir") or "unknown"))
        if not is_terminal_lead_status(status):
            actionable_count += 1

    if missing:
        status = "failed"
    elif actionable_count:
        status = "has-actionable-leads"
    elif leads:
        status = "leads-indexed"
    else:
        status = "no-leads"

    top_actionable = [
        compact_rollup_lead(lead)
        for lead in leads
        if not is_terminal_lead_status(lead.get("status"))
    ][:20]

    return {
        "generated_at": utc_now(),
        "status": status,
        "target": target,
        "profile": profile_summary(profile),
        "artifact_dir": str(artifact_dir),
        "mode": "rollup",
        "summary": {
            "runs": len(runs),
            "leads": len(leads),
            "actionable_leads": actionable_count,
            "missing_lead_portfolios": missing,
            "status_counts": dict(sorted(status_counts.items())),
            "priority_counts": dict(sorted(priority_counts.items())),
            "type_counts": dict(sorted(type_counts.items())),
            "scope_decision_counts": dict(sorted(scope_counts.items())),
            "source_counts": dict(sorted(source_counts.items())),
            "run_status_counts": dict(sorted(run_status_counts.items())),
        },
        "runs": runs,
        "top_actionable_leads": top_actionable,
        "leads": leads,
        "artifact_refs": {
            "lead_portfolio": LEAD_PORTFOLIO_ARTIFACT,
        },
        "safety": (
            "Read-only lead portfolio rollup. It reads child lead-portfolio artifacts only and does not send "
            "HTTP requests, invoke Burp, run Burp Scanner, sign wallets, submit transactions, or fetch external hosts."
        ),
    }


