def artifact_health_repair_commands(
    artifact_health: dict[str, Any],
    *,
    profile: dict[str, Any] | None,
    fallback_artifact_dir: Path,
    no_write_preview: bool = False,
) -> list[dict[str, Any]]:
    refs: list[dict[str, Any]] = []
    seen: set[str] = set()

    def add_repair_command(
        *,
        artifact_dir: Path,
        subcommand: str,
        source: str,
        reason: str,
        artifacts: list[str],
    ) -> None:
        command_subcommand = subcommand
        if no_write_preview:
            command_subcommand = ARTIFACT_REPAIR_NO_WRITE_PREVIEW_COMMANDS.get(subcommand, "")
            if not command_subcommand:
                return
        command = validation_command_for_artifact_dir(artifact_dir, command_subcommand, profile=profile)
        if command in seen:
            return
        ref = validation_command_ref(command, source=source, item_status="ready")
        if ref.get("classification") != "ready":
            return
        seen.add(command)
        ref["artifact_dir"] = repo_relative_or_absolute(artifact_dir)
        ref["reason"] = reason
        ref["repair_mode"] = "no-write-preview" if no_write_preview else "write-refresh"
        ref["repair_subcommand"] = subcommand
        ref["repair_artifacts"] = ordered_unique_strings(artifacts)
        refs.append(ref)

    for directory in artifact_health.get("directories", []) or []:
        if not isinstance(directory, dict):
            continue
        raw_dir = str(directory.get("artifact_dir") or "").strip()
        artifact_dir = Path(raw_dir).resolve() if raw_dir else fallback_artifact_dir.resolve()
        missing_by_command: dict[str, list[str]] = {}
        for name in directory.get("missing_required", []) or []:
            artifact_name = str(name)
            subcommand = OFFLINE_ARTIFACT_REPAIR_COMMANDS.get(artifact_name)
            if subcommand:
                missing_by_command.setdefault(subcommand, []).append(artifact_name)
        repair_rank = {subcommand: index for index, subcommand in enumerate(ARTIFACT_REPAIR_COMMAND_ORDER)}
        for subcommand, names in sorted(
            missing_by_command.items(),
            key=lambda item: (repair_rank.get(item[0], len(repair_rank)), item[0]),
        ):
            add_repair_command(
                artifact_dir=artifact_dir,
                subcommand=subcommand,
                source=f"artifact-health:{repo_relative_or_absolute(artifact_dir)}:missing:{subcommand}",
                reason="Offline artifact refresh for missing required artifacts.",
                artifacts=names,
            )

        stale_by_command: dict[str, list[str]] = {}
        for issue in directory.get("stale_inputs", []) or []:
            if not isinstance(issue, dict):
                continue
            subcommand = OFFLINE_STALE_REPAIR_COMMANDS.get(str(issue.get("reason") or ""))
            if not subcommand:
                continue
            file_name = str(issue.get("file") or "unknown")
            stale_by_command.setdefault(subcommand, []).append(file_name)
        for subcommand, names in sorted(
            stale_by_command.items(),
            key=lambda item: (repair_rank.get(item[0], len(repair_rank)), item[0]),
        ):
            add_repair_command(
                artifact_dir=artifact_dir,
                subcommand=subcommand,
                source=f"artifact-health:{repo_relative_or_absolute(artifact_dir)}:stale:{subcommand}",
                reason="Offline artifact refresh for stale derived artifacts.",
                artifacts=names,
            )
    return refs


def build_iteration_decision_from_plan(
    *,
    target: str,
    profile: dict[str, Any] | None,
    artifact_dir: Path,
    validation_plan: dict[str, Any],
    artifact_health: dict[str, Any],
    current_resource_snapshot: dict[str, Any] | None,
    limit: int,
) -> dict[str, Any]:
    commands = collect_iteration_command_sets(validation_plan)
    offline = commands["offline"]
    resource_checks = commands["resource_checks"]
    active_after_gate = commands["active_after_gate"]
    blocked = commands["blocked"]
    resource_preflight = validation_resource_preflight_summary(current_resource_snapshot)
    resource_status = str(resource_preflight.get("status") or "not-run")
    resource_budget = (
        resource_preflight.get("resource_budget")
        if isinstance(resource_preflight.get("resource_budget"), dict)
        else {}
    )
    if not resource_budget and resource_status in {"healthy", "warning"}:
        resource_budget = build_resource_budget(
            resource_status,
            [str(item) for item in resource_preflight.get("warnings", []) or []],
            resource_preflight.get("memory", {}) if isinstance(resource_preflight.get("memory"), dict) else {},
        )
        resource_preflight["resource_budget"] = resource_budget
    resource_budget_mode = str(
        resource_budget.get("mode")
        or ("unchecked" if resource_status == "not-run" else resource_status)
    )
    offline_preview_limit = limit
    raw_offline_preview_limit = resource_budget.get("offline_command_preview_limit")
    try:
        offline_preview_limit = min(limit, max(1, int(raw_offline_preview_limit)))
    except (TypeError, ValueError):
        if resource_status not in {"healthy", "not-run"}:
            offline_preview_limit = min(limit, DEFAULT_RESOURCE_DEGRADED_OFFLINE_COMMAND_LIMIT)
    artifact_health_status = artifact_summary_status(artifact_health)
    repair_no_write_preview = resource_status not in {"healthy", "not-run"}
    artifact_repair = artifact_health_repair_commands(
        artifact_health,
        profile=profile,
        fallback_artifact_dir=artifact_dir,
        no_write_preview=repair_no_write_preview,
    )
    allowed_command_summary = command_safety_summary([*artifact_repair, *offline, *resource_checks, *active_after_gate])
    blocked_command_summary = command_safety_summary(blocked)
    artifact_health_blocks_active = artifact_health_status in {"failed", "needs-human-review"}
    resource_blocks_active = bool(active_after_gate and resource_status not in {"healthy", "not-run"})

    actions: list[dict[str, Any]] = []
    if offline:
        offline_reason = "Read-only planning commands can run under current resource pressure."
        if resource_status not in {"healthy", "not-run"}:
            offline_reason = (
                f"Resource budget mode is {resource_budget_mode}; run only capped no-write offline planning commands."
            )
        actions.append(
            iteration_action(
                action_id="offline-planning",
                status="ready",
                kind="offline",
                reason=offline_reason,
                commands=offline,
                limit=offline_preview_limit,
            )
        )
    if artifact_health_blocks_active and artifact_repair:
        repair_reason = "Artifact health is not clean; run offline artifact refresh commands before active validation."
        if repair_no_write_preview:
            repair_reason = (
                f"Artifact health is not clean and resource budget mode is {resource_budget_mode}; "
                "run only capped no-write artifact repair previews."
            )
        actions.append(
            iteration_action(
                action_id="artifact-repair",
                status="ready",
                kind="artifact-repair",
                reason=repair_reason,
                commands=artifact_repair,
                limit=offline_preview_limit,
            )
        )
    if active_after_gate:
        active_status = "ready-after-resource-gate"
        active_reason = "Active commands are constrained and still require the resource-check command immediately before execution."
        if resource_blocks_active:
            active_status = "blocked-resource"
            active_reason = (
                f"Current resource preflight is {resource_budget_mode}; do not run active validation commands."
            )
            if artifact_health_blocks_active:
                active_reason += " Artifact health also blocks active validation."
        elif artifact_health_blocks_active:
            active_status = "blocked-artifact-health"
            active_reason = "Artifact health is not clean; refresh required artifacts before active validation commands."
        actions.append(
            iteration_action(
                action_id="active-validation",
                status=active_status,
                kind="active-validation",
                reason=active_reason,
                commands=active_after_gate,
                limit=offline_preview_limit if active_status.startswith("blocked") else limit,
            )
        )
    if resource_checks:
        actions.append(
            iteration_action(
                action_id="resource-check",
                status="ready",
                kind="local-gate",
                reason="Local /proc resource check; no target requests are sent.",
                commands=resource_checks,
                limit=limit,
            )
        )
    if blocked:
        actions.append(
            iteration_action(
                action_id="blocked-commands",
                status="blocked-command-safety",
                kind="blocked",
                reason="These commands are isolated from unattended execution.",
                commands=blocked,
                limit=limit,
            )
        )

    if offline or artifact_repair:
        status = "ready-offline"
    elif artifact_health_blocks_active:
        status = "blocked-artifact-health"
    elif blocked_command_summary.get("unsafe_template_count") or blocked_command_summary.get("blocked_external"):
        status = "blocked-command-safety"
    elif active_after_gate and resource_blocks_active:
        status = "blocked-resource"
    elif active_after_gate:
        status = "ready-active-validation"
    elif validation_plan.get("items"):
        status = "parked"
    else:
        status = "no-validation-items"

    return {
        "generated_at": utc_now(),
        "status": status,
        "target": target,
        "profile": profile_summary(profile),
        "artifact_dir": str(artifact_dir),
        "mode": validation_plan.get("mode") or "single-run",
        "summary": {
            "validation_plan": validation_plan.get("status"),
            "artifact_health": artifact_health_status,
            "current_resource_snapshot": resource_status,
            "resource_budget_mode": resource_budget_mode,
            "offline_command_preview_limit": offline_preview_limit,
            "burp_history_count_limit": resource_budget.get("burp_history_count_limit"),
            "validation_items": len(validation_plan.get("items", []) or []),
            "artifact_repair_commands": len(artifact_repair),
            "offline_commands": len(offline),
            "resource_check_commands": len(resource_checks),
            "active_after_resource_gate_commands": len(active_after_gate),
            "artifact_health_blocked_active_commands": len(active_after_gate) if artifact_health_blocks_active else 0,
            "resource_blocked_active_commands": len(active_after_gate) if resource_blocks_active else 0,
            "blocked_commands": len(blocked),
            "command_safety": allowed_command_summary,
            "blocked_command_safety": blocked_command_summary,
        },
        "resource_preflight": resource_preflight,
        "artifact_health": {
            "status": artifact_health_status,
            "summary": artifact_health.get("summary", {}) if isinstance(artifact_health, dict) else {},
        },
        "actions": actions,
        "artifact_refs": {
            "validation_plan": VALIDATION_PLAN_ARTIFACT,
            "artifact_health": "artifact-health.json",
            "resource_snapshot": RESOURCE_SNAPSHOT_ARTIFACT,
        },
        "safety": (
            "Read-only iteration decision. It does not execute commands, send requests, invoke Burp, "
            "run scanners, sign wallets, submit transactions, or fetch external hosts."
        ),
    }


def build_iteration_decision(
    *,
    target: str,
    profile: dict[str, Any] | None,
    artifact_dir: Path,
    check_dirs: list[Path],
    limit: int,
    current_resource_snapshot: dict[str, Any] | None,
) -> dict[str, Any]:
    if check_dirs:
        validation_plan = build_validation_plan_rollup(
            target=target,
            profile=profile,
            artifact_dir=artifact_dir,
            check_dirs=check_dirs,
            limit=limit,
            current_resource_snapshot=current_resource_snapshot,
        )
        artifact_health = build_artifact_health(check_dirs)
    else:
        validation_plan = build_validation_plan_run(
            target=target,
            profile=profile,
            artifact_dir=artifact_dir,
            limit=limit,
            current_resource_snapshot=current_resource_snapshot,
        )
        artifact_health = build_artifact_health([artifact_dir])
    return build_iteration_decision_from_plan(
        target=target,
        profile=profile,
        artifact_dir=artifact_dir,
        validation_plan=validation_plan,
        artifact_health=artifact_health,
        current_resource_snapshot=current_resource_snapshot,
        limit=limit,
    )


def read_http_headers_from_socket(sock: socket.socket, *, max_bytes: int = 65536) -> bytes:
    chunks: list[bytes] = []
    total = 0
    while total < max_bytes:
        chunk = sock.recv(4096)
        if not chunk:
            break
        chunks.append(chunk)
        total += len(chunk)
        if b"\r\n\r\n" in b"".join(chunks):
            break
    return b"".join(chunks)[:max_bytes]


def parse_http_status_and_headers(raw: bytes) -> tuple[int | None, dict[str, str], str]:
    text = raw.decode("iso-8859-1", errors="replace")
    head = text.split("\r\n\r\n", 1)[0]
    lines = head.split("\r\n") if head else []
    status = None
    if lines:
        parts = lines[0].split()
        if len(parts) >= 2 and parts[1].isdigit():
            status = int(parts[1])
    headers: dict[str, str] = {}
    for line in lines[1:]:
        key, sep, value = line.partition(":")
        if sep:
            headers[key.strip().lower()] = value.strip()
    return status, headers, lines[0] if lines else ""


def websocket_handshake_baseline_once(
    *,
    url: str,
    origin: str,
    proxy: str | None,
    timeout: int,
) -> dict[str, Any]:
    parsed = urllib.parse.urlparse(url)
    if parsed.scheme not in {"ws", "wss"} or not parsed.hostname:
        return {"status": "blocked-invalid-url", "expected": False, "error": "candidate URL must be ws:// or wss://"}
    host = parsed.hostname
    port = parsed.port or (443 if parsed.scheme == "wss" else 80)
    path = urllib.parse.urlunparse(("", "", parsed.path or "/", "", parsed.query, ""))
    proxy_parsed = urllib.parse.urlparse(proxy or "")
    started = time.monotonic()
    raw_sock: socket.socket | None = None
    sock: socket.socket | ssl.SSLSocket | None = None
    sec_key = base64.b64encode(os.urandom(16)).decode("ascii")
    try:
        if proxy:
            if proxy_parsed.scheme != "http" or not proxy_parsed.hostname:
                return {"status": "blocked-invalid-proxy", "expected": False, "error": "proxy must be an http://host:port URL"}
            raw_sock = socket.create_connection((proxy_parsed.hostname, proxy_parsed.port or 8080), timeout=timeout)
            raw_sock.settimeout(timeout)
            connect_target = f"{host}:{port}"
            connect_request = (
                f"CONNECT {connect_target} HTTP/1.1\r\n"
                f"Host: {connect_target}\r\n"
                "Proxy-Connection: close\r\n"
                "\r\n"
            ).encode("ascii")
            raw_sock.sendall(connect_request)
            proxy_raw = read_http_headers_from_socket(raw_sock)
            proxy_status, _proxy_headers, proxy_status_line = parse_http_status_and_headers(proxy_raw)
            if proxy_status != 200:
                raw_sock.close()
                return {
                    "status": "proxy-connect-failed",
                    "expected": False,
                    "proxy_status": proxy_status,
                    "proxy_status_line": proxy_status_line[:160],
                    "duration_ms": round((time.monotonic() - started) * 1000),
                }
        else:
            raw_sock = socket.create_connection((host, port), timeout=timeout)
            raw_sock.settimeout(timeout)

        if parsed.scheme == "wss":
            context = ssl._create_unverified_context() if proxy else ssl.create_default_context()
            sock = context.wrap_socket(raw_sock, server_hostname=host)
        else:
            sock = raw_sock
        sock.settimeout(timeout)
        host_header = parsed.netloc
        request = (
            f"GET {path} HTTP/1.1\r\n"
            f"Host: {host_header}\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            f"Sec-WebSocket-Key: {sec_key}\r\n"
            "Sec-WebSocket-Version: 13\r\n"
            f"Origin: {origin}\r\n"
            "User-Agent: InferForge-WS-Handshake/0.1\r\n"
            "\r\n"
        ).encode("ascii")
        sock.sendall(request)
        raw_response = read_http_headers_from_socket(sock)
        response_status, response_headers, response_status_line = parse_http_status_and_headers(raw_response)
        expected = response_status in {101, 400, 401, 403, 404, 426}
        result_status = "handshake-upgraded" if response_status == 101 else "handshake-rejected"
        if response_status is None:
            result_status = "transport-error"
            expected = False
        elif response_status >= 500:
            result_status = "server-error"
            expected = False
        return {
            "status": result_status,
            "expected": expected,
            "url": url,
            "response_status": response_status,
            "response_status_line": response_status_line[:160],
            "response_headers": redact_headers(response_headers),
            "duration_ms": round((time.monotonic() - started) * 1000),
            "request": {
                "method": "GET",
                "path": path,
                "host": host_header,
                "origin": origin,
                "user_agent": "InferForge-WS-Handshake/0.1",
                "sec_websocket_key_sha256": hashlib.sha256(sec_key.encode("ascii")).hexdigest(),
            },
            "frames_sent": 0,
        }
    except (OSError, ssl.SSLError, TimeoutError) as error:
        return {
            "status": "transport-error",
            "expected": False,
            "url": url,
            "error": redacted_error_summary(error),
            "duration_ms": round((time.monotonic() - started) * 1000),
            "frames_sent": 0,
        }
    finally:
        if sock is not None:
            with contextlib.suppress(OSError):
                sock.close()
        elif raw_sock is not None:
            with contextlib.suppress(OSError):
                raw_sock.close()


def contains_unredacted_secret_text(value: str) -> bool:
    for match in SECRET_TEXT_RE.finditer(value):
        prefix = match.group(1) or match.group(2) or ""
        secret = match.group(0)[len(prefix) :].strip()
        if secret and secret.lower() not in {"[redacted]", "redacted"}:
            return True
    return False


def redact_headers(headers: dict[str, str]) -> dict[str, str]:
    redacted = {}
    for key, value in headers.items():
        if key.lower() in SENSITIVE_HEADER_NAMES:
            redacted[key] = REDACTED_VALUE
        else:
            redacted[key] = value
    return redacted


def sensitive_param_name(name: str) -> bool:
    lowered = name.lower()
    return any(token in lowered for token in ["token", "secret", "password", "api_key", "apikey", "key", "auth", "cookie"])


def redact_observed_value(key: str, value: str, *, sensitive: bool = False) -> str:
    if sensitive or sensitive_param_name(key):
        return REDACTED_VALUE
    redacted = redact_text(value, max_chars=500)
    return REDACTED_VALUE if redacted is None else redacted


def parse_cookie_header(value: str) -> dict[str, str]:
    cookies: dict[str, str] = {}
    for part in value.split(";"):
        item = part.strip()
        if not item:
            continue
        if "=" in item:
            key, cookie_value = item.split("=", 1)
        else:
            key, cookie_value = item, ""
        key = key.strip()
        if key:
            cookies[key] = cookie_value.strip()
    return cookies


def parse_query_context(path: str) -> dict[str, list[str]]:
    parsed = urllib.parse.urlparse(path)
    query: dict[str, list[str]] = {}
    for key, values in urllib.parse.parse_qs(parsed.query, keep_blank_values=True).items():
        query[key] = [redact_observed_value(key, str(value)) for value in values]
    return query


def build_request_context(method: str, path: str, headers: dict[str, str] | None = None, host: str | None = None) -> dict[str, Any]:
    raw_headers = headers or {}
    normalized_headers = {str(key).lower(): str(value) for key, value in raw_headers.items()}
    observed_host = host or normalized_headers.get("host", "")
    redacted_headers = {
        key: redact_observed_value(key, value, sensitive=key in SENSITIVE_HEADER_NAMES)
        for key, value in normalized_headers.items()
    }
    cookie_header = normalized_headers.get("cookie", "")
    raw_cookies = {} if cookie_header == REDACTED_VALUE else parse_cookie_header(cookie_header)
    cookies = {name: REDACTED_VALUE for name in raw_cookies}
    query = parse_query_context(path)
    return {
        "method": str(method).upper(),
        "path": path,
        "path_without_query": path.split("?", 1)[0],
        "host": observed_host,
        "headers": redacted_headers,
        "header_names": sorted(redacted_headers),
        "query": query,
        "query_keys": sorted(query),
        "cookies": cookies,
        "cookie_names": sorted(cookies),
        "redaction": {
            "sensitive_headers": sorted(key for key in normalized_headers if key in SENSITIVE_HEADER_NAMES),
            "cookie_values": "redacted" if cookies else "absent",
        },
    }


def request_context_signature(context: dict[str, Any]) -> str:
    return json.dumps(
        {
            "method": context.get("method"),
            "path": context.get("path"),
            "host": context.get("host"),
            "headers": context.get("headers", {}),
            "query": context.get("query", {}),
            "cookie_names": context.get("cookie_names", []),
        },
        sort_keys=True,
    )


def parse_http_headers(lines: list[str]) -> dict[str, str]:
    headers: dict[str, str] = {}
    for line in lines:
        if not line or ":" not in line:
            continue
        if line.startswith(":") and ":" in line[1:]:
            key, value = line[1:].split(":", 1)
            headers[f":{key.strip().lower()}"] = value.strip()
            continue
        key, value = line.split(":", 1)
        headers[key.strip().lower()] = value.strip()
    return headers


def split_http_message(raw: str) -> tuple[str, list[str], str]:
    head, sep, body = raw.partition("\r\n\r\n")
    if not sep:
        head, _, body = raw.partition("\n\n")
    lines = head.replace("\r\n", "\n").splitlines()
    start_line = lines[0] if lines else ""
    return start_line, lines[1:], body


def normalize_request_path(target: str) -> str:
    parsed = urllib.parse.urlparse(target)
    if parsed.scheme and parsed.netloc:
        path = parsed.path or "/"
        return urllib.parse.urlunparse(("", "", path, "", parsed.query, ""))
    return target or "/"


def parse_raw_http_request(raw: str) -> dict[str, Any]:
    start_line, header_lines, _ = split_http_message(raw)
    parts = start_line.split()
    headers = parse_http_headers(header_lines)
    method = parts[0].upper() if parts else str(headers.get(":method") or "").upper()
    path = normalize_request_path(parts[1]) if len(parts) > 1 else normalize_request_path(headers.get(":path") or "/")
    host = headers.get("host") or headers.get(":authority") or ""
    return {
        "method": method,
        "path": path,
        "headers": headers,
        "host": host,
        "user_agent": headers.get("user-agent", ""),
    }


def parse_raw_http_response(raw: str) -> dict[str, Any]:
    if not raw:
        return {"status": None, "headers": {}, "body": ""}

    start_line, header_lines, body = split_http_message(raw)
    parts = start_line.split()
    status = None
    if len(parts) > 1:
        try:
            status = int(parts[1])
        except ValueError:
            status = None
    headers = parse_http_headers(header_lines)
    if status is None and headers.get(":status"):
        try:
            status = int(str(headers.get(":status")))
        except ValueError:
            status = None
    return {"status": status, "headers": headers, "body": body}


def parse_http_date(value: str | None) -> str | None:
    if not value:
        return None
    try:
        parsed = parsedate_to_datetime(value)
    except (TypeError, ValueError, IndexError, OverflowError):
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def parse_json_object(text: str) -> dict[str, Any] | None:
    try:
        parsed = json.loads(text)
    except json.JSONDecodeError:
        return None
    return parsed if isinstance(parsed, dict) else None


def is_placeholder_env_value(value: str | None) -> bool:
    return bool(value and PLACEHOLDER_ENV_RE.fullmatch(value.strip()))


def parse_dotenv_file(path: Path) -> dict[str, str]:
    values: dict[str, str] = {}
    if not path.exists():
        return values

    for line in path.read_text(encoding="utf-8", errors="replace").splitlines():
        stripped = line.strip()
        if not stripped or stripped.startswith("#") or "=" not in stripped:
            continue
        key, value = stripped.split("=", 1)
        values[key.strip()] = value.strip().strip('"').strip("'")
    return values


def classify_env_value(value: str | None, *, secret: bool) -> dict[str, Any]:
    if value is None:
        return {"status": "missing"}
    if value == "":
        return {"status": "empty"}
    if is_placeholder_env_value(value):
        return {"status": "placeholder"}
    result: dict[str, Any] = {"status": "configured"}
    if not secret:
        result["value"] = value
    return result


def is_websocket_upgrade_observation(request: dict[str, Any], response: dict[str, Any]) -> bool:
    request_headers = request.get("headers", {})
    response_headers = response.get("headers", {})
    request_upgrade = request_headers.get("upgrade", "").lower() == "websocket"
    response_upgrade = response_headers.get("upgrade", "").lower() == "websocket"
    request_connection = request_headers.get("connection", "").lower()
    response_connection = response_headers.get("connection", "").lower()
    return (
        response.get("status") == 101
        and request_upgrade
        and response_upgrade
        and "upgrade" in request_connection
        and "upgrade" in response_connection
    )


def decode_mcp_text_payload(text: str) -> str:
    stripped = text.strip()
    if not stripped:
        return ""

    try:
        parsed = json.loads(stripped, strict=False)
    except json.JSONDecodeError:
        return text

    if isinstance(parsed, list) and all(isinstance(item, dict) for item in parsed):
        chunks = [
            item.get("text", "")
            for item in parsed
            if item.get("type") == "text" and isinstance(item.get("text"), str)
        ]
        if chunks:
            return "\n\n".join(chunks)

    if isinstance(parsed, dict) and isinstance(parsed.get("text"), str):
        return parsed["text"]

    return text


def decode_loose_json_string_fragment(value: str) -> str:
    try:
        return json.loads(f'"{value}"', strict=False)
    except json.JSONDecodeError:
        pass

    decoded: list[str] = []
    index = 0
    while index < len(value):
        char = value[index]
        if char != "\\" or index + 1 >= len(value):
            decoded.append(char)
            index += 1
            continue

        escaped = value[index + 1]
        replacements = {
            '"': '"',
            "\\": "\\",
            "/": "/",
            "b": "\b",
            "f": "\f",
            "n": "\n",
            "r": "\r",
            "t": "\t",
        }
        if escaped == "u" and index + 6 <= len(value):
            hex_value = value[index + 2 : index + 6]
            try:
                decoded.append(chr(int(hex_value, 16)))
                index += 6
                continue
            except ValueError:
                pass
        if escaped in replacements:
            decoded.append(replacements[escaped])
            index += 2
            continue
        decoded.append(escaped)
        index += 2

    return "".join(decoded)


def parse_loose_burp_mcp_history_item(record: str) -> dict[str, Any] | None:
    stripped = record.strip()
    if not stripped:
        return None

    try:
        parsed = json.loads(stripped, strict=False)
    except json.JSONDecodeError:
        parsed = None
    if isinstance(parsed, dict):
        return parsed

    request_marker = '"request":"'
    response_marker = '","response":"'
    request_start = stripped.find(request_marker)
    if request_start < 0:
        return None
    request_start += len(request_marker)
    response_start = stripped.find(response_marker, request_start)
    if response_start < 0:
        return None

    request_fragment = stripped[request_start:response_start]
    response_fragment_start = response_start + len(response_marker)
    notes_marker = '","notes":"'
    notes_start = stripped.rfind(notes_marker)
    truncated = notes_start < response_fragment_start
    notes_fragment = ""

    if truncated:
        response_fragment = stripped[response_fragment_start:]
        if response_fragment.endswith('"}'):
            response_fragment = response_fragment[:-2]
            truncated = False
        elif response_fragment.endswith("}"):
            response_fragment = response_fragment[:-1]
    else:
        response_fragment = stripped[response_fragment_start:notes_start]
        notes_value_start = notes_start + len(notes_marker)
        notes_value_end = stripped.rfind('"}')
        if notes_value_end < notes_value_start:
            notes_value_end = len(stripped)
            truncated = True
        notes_fragment = stripped[notes_value_start:notes_value_end]

    item: dict[str, Any] = {
        "request": decode_loose_json_string_fragment(request_fragment),
        "response": decode_loose_json_string_fragment(response_fragment),
        "notes": decode_loose_json_string_fragment(notes_fragment),
    }
    if truncated:
        item["_burp_mcp_truncated"] = True
    return item


def parse_loose_burp_mcp_history_items(payload: str) -> list[dict[str, Any]]:
    stripped = payload.strip()
    if not stripped:
        return []

    records = re.split(r"\n\s*\n(?=\{\"request\"\s*:)", stripped)
    if len(records) <= 1:
        records = stripped.splitlines()

    items: list[dict[str, Any]] = []
    for record in records:
        item = parse_loose_burp_mcp_history_item(record)
        if item is not None:
            items.append(item)
    return items


def parse_burp_mcp_history_items(text: str) -> list[dict[str, Any]]:
    payload = decode_mcp_text_payload(text)
    stripped = payload.strip()
    if not stripped:
        return []

    try:
        parsed = json.loads(stripped)
    except json.JSONDecodeError:
        parsed = None

    if isinstance(parsed, list):
        return [item for item in parsed if isinstance(item, dict)]
    if isinstance(parsed, dict):
        return [parsed]

    decoder = json.JSONDecoder(strict=False)
    index = 0
    items: list[dict[str, Any]] = []
    while index < len(payload):
        while index < len(payload) and payload[index].isspace():
            index += 1
        if index >= len(payload):
            break
        try:
            item, next_index = decoder.raw_decode(payload, index)
        except json.JSONDecodeError as error:
            loose_items = parse_loose_burp_mcp_history_items(payload)
            if loose_items:
                return loose_items
            snippet = payload[index:index + 120].replace("\n", "\\n")
            raise ValueError(f"Could not parse Burp MCP history item near offset {index}: {snippet}") from error
        if isinstance(item, dict):
            items.append(item)
        index = next_index

    return items


def normalize_burp_history_items(
    items: list[dict[str, Any]],
    *,
    target_netloc: str | None,
    source: str,
) -> list[dict[str, Any]]:
    observations: list[dict[str, Any]] = []

    for item in items:
        request = parse_raw_http_request(str(item.get("request") or ""))
        response = parse_raw_http_response(str(item.get("response") or ""))
        host = request["host"]
        if target_netloc and host != target_netloc:
            continue

        response_headers = response["headers"]
        response_body = response["body"]
        method = "WS" if is_websocket_upgrade_observation(request, response) else request["method"]
        request_context = build_request_context(method, request["path"], request.get("headers", {}), host)
        observations.append(
            {
                "ts": parse_http_date(response_headers.get("date")) or utc_now(),
                "source": source,
                "method": method,
                "path": request["path"],
                "host": host,
                "status": response["status"],
                "content_type": response_headers.get("content-type"),
                "request_user_agent": request["user_agent"],
                "request_context": request_context,
                "response_sample": redact_text(response_body, max_chars=500),
                "notes": item.get("notes", ""),
            }
        )

    return observations


def dedupe_observations(rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[Any, ...]] = set()
    deduped: list[dict[str, Any]] = []
    for row in rows:
        key = (
            row.get("method"),
            row.get("path"),
            row.get("host"),
            row.get("status"),
            row.get("request_user_agent"),
            row.get("response_sample"),
        )
        if key in seen:
            continue
        seen.add(key)
        deduped.append(row)
    return deduped


def origin_for(target: str) -> str:
    parsed = urllib.parse.urlparse(target)
    return f"{parsed.scheme}://{parsed.netloc}"


def target_to_ws(target: str) -> str:
    parsed = urllib.parse.urlparse(target)
    scheme = "wss" if parsed.scheme == "https" else "ws"
    return urllib.parse.urlunparse((scheme, parsed.netloc, "", "", "", ""))


def socket_open(host: str, port: int, timeout: float = 1.5) -> bool:
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except OSError:
        return False


def target_lock_key(target: str) -> str:
    parsed = urllib.parse.urlparse(target)
    key = f"{parsed.scheme or 'http'}://{parsed.netloc or parsed.path}".rstrip("/")
    digest = hashlib.sha256(key.encode("utf-8")).hexdigest()[:16]
    return f"target-{digest}"


def process_is_alive(pid: int | None) -> bool:
    if not pid or pid <= 0:
        return False
    try:
        os.kill(pid, 0)
        return True
    except ProcessLookupError:
        return False
    except PermissionError:
        return True
    except OSError:
        return False


def read_lock_metadata(path: Path) -> dict[str, Any]:
    try:
        return json.loads(read_text(path))
    except (OSError, json.JSONDecodeError):
        return {}


class TargetProbeLock:
    def __init__(self, target: str, *, purpose: str, stale_after_seconds: int = 3600) -> None:
        self.target = target.rstrip("/")
        self.purpose = purpose
        self.stale_after_seconds = stale_after_seconds
        self.path = DEFAULT_ARTIFACT_DIR / "locks" / f"{target_lock_key(self.target)}.json"
        self.acquired = False

    def __enter__(self) -> "TargetProbeLock":
        self.path.parent.mkdir(parents=True, exist_ok=True)
        while True:
            try:
                fd = os.open(str(self.path), os.O_CREAT | os.O_EXCL | os.O_WRONLY)
            except FileExistsError:
                existing = read_lock_metadata(self.path)
                pid = existing.get("pid")
                age = time.time() - self.path.stat().st_mtime if self.path.exists() else 0
                stale = age > self.stale_after_seconds or not process_is_alive(int(pid) if isinstance(pid, int) else None)
                if stale:
                    try:
                        self.path.unlink()
                    except FileNotFoundError:
                        pass
                    continue
                raise RuntimeError(
                    "Active probes are already running for this target: "
                    f"target={existing.get('target', self.target)} "
                    f"purpose={existing.get('purpose', 'unknown')} "
                    f"pid={existing.get('pid', 'unknown')} "
                    f"lock={self.path}"
                )
            with os.fdopen(fd, "w", encoding="utf-8") as handle:
                json.dump(
                    {
                        "created_at": utc_now(),
                        "pid": os.getpid(),
                        "target": self.target,
                        "purpose": self.purpose,
                        "safety": "Prevents concurrent active probes from creating resource-control false positives.",
                    },
                    handle,
                    indent=2,
                    sort_keys=True,
                )
                handle.write("\n")
            self.acquired = True
            return self

    def __exit__(self, exc_type: Any, exc: Any, tb: Any) -> None:
        if not self.acquired:
            return
        try:
            existing = read_lock_metadata(self.path)
            if existing.get("pid") == os.getpid():
                self.path.unlink()
        except FileNotFoundError:
            pass
        finally:
            self.acquired = False


def command_result(cmd: list[str], cwd: Path = ROOT, timeout: int = 10) -> dict[str, Any]:
    try:
        proc = subprocess.run(
            cmd,
            cwd=str(cwd),
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            timeout=timeout,
            check=False,
        )
        return {
            "ok": proc.returncode == 0,
            "returncode": proc.returncode,
            "output": proc.stdout[-4000:],
        }
    except (OSError, subprocess.TimeoutExpired) as error:
        return {"ok": False, "returncode": None, "output": str(error)}


class McpSseClient:
    def __init__(self, url: str, *, timeout: int = 10) -> None:
        self.url = url.rstrip("/") + "/"
        self.timeout = timeout
        self.response: Any = None
        self.message_url: str | None = None
        self.next_id = 1

    def __enter__(self) -> "McpSseClient":
        request = urllib.request.Request(
            self.url,
            headers={"Accept": "text/event-stream"},
        )
        self.response = urllib.request.urlopen(request, timeout=self.timeout)
        endpoint = self._read_sse_data(expected_event="endpoint")
        if not endpoint:
            raise RuntimeError("Burp MCP SSE endpoint did not provide a session endpoint")
        self.message_url = urllib.parse.urljoin(self.url, endpoint)
        self._initialize()
        return self

    def __exit__(self, exc_type: Any, exc: Any, tb: Any) -> None:
        if self.response:
            self.response.close()

    def _readline(self) -> str:
        if not self.response:
            raise RuntimeError("MCP SSE connection is not open")
        return self.response.readline().decode("utf-8", errors="replace").rstrip("\r\n")

    def _read_sse_data(self, *, expected_event: str | None = None, request_id: int | None = None) -> Any:
        event: str | None = None
        data_lines: list[str] = []
        while True:
            line = self._readline()
            if line == "":
                if not data_lines:
                    continue
                data = "\n".join(data_lines)
                if expected_event and event != expected_event:
                    event = None
                    data_lines = []
                    continue
                if request_id is None:
                    return data
                try:
                    payload = json.loads(data)
                except json.JSONDecodeError:
                    event = None
                    data_lines = []
                    continue
                if payload.get("id") == request_id:
                    if payload.get("error"):
                        raise RuntimeError(json.dumps(payload["error"], sort_keys=True))
                    return payload.get("result")
                event = None
                data_lines = []
                continue
            if line.startswith("event:"):
                event = line.split(":", 1)[1].strip()
            elif line.startswith("data:"):
                data_lines.append(line.split(":", 1)[1].strip())

    def _post(self, payload: dict[str, Any]) -> None:
        if not self.message_url:
            raise RuntimeError("MCP message endpoint is not ready")
        data = json.dumps(payload).encode("utf-8")
        request = urllib.request.Request(
            self.message_url,
            data=data,
            method="POST",
            headers={"Content-Type": "application/json"},
        )
        with urllib.request.urlopen(request, timeout=self.timeout) as response:
            response.read()

    def request(self, method: str, params: dict[str, Any] | None = None) -> Any:
        request_id = self.next_id
        self.next_id += 1
        self._post(
            {
                "jsonrpc": "2.0",
                "id": request_id,
                "method": method,
                "params": params or {},
            }
        )
        return self._read_sse_data(request_id=request_id)

    def notify(self, method: str, params: dict[str, Any] | None = None) -> None:
        self._post({"jsonrpc": "2.0", "method": method, "params": params or {}})

    def _initialize(self) -> None:
        self.request(
            "initialize",
            {
                "protocolVersion": "2024-11-05",
                "capabilities": {},
                "clientInfo": {"name": "inferforge", "version": "0.1"},
            },
        )
        self.notify("notifications/initialized", {})

    def call_tool(self, name: str, arguments: dict[str, Any] | None = None) -> dict[str, Any]:
        result = self.request("tools/call", {"name": name, "arguments": arguments or {}})
        return result if isinstance(result, dict) else {"raw": result}

    def list_tools(self) -> list[dict[str, Any]]:
        result = self.request("tools/list")
        if isinstance(result, dict) and isinstance(result.get("tools"), list):
            return [item for item in result["tools"] if isinstance(item, dict)]
        return []


def mcp_tool_text(result: dict[str, Any]) -> str:
    content = result.get("content", [])
    chunks = [
        item.get("text", "")
        for item in content
        if isinstance(item, dict) and item.get("type") == "text" and isinstance(item.get("text"), str)
    ]
    if chunks:
        return "\n\n".join(chunks)
    if "raw" in result:
        return str(result["raw"])
    return json.dumps(result, sort_keys=False)


def mcp_audit_argument_value(key: str, value: Any) -> Any:
    lowered = key.lower()
    secret_markers = ["authorization", "cookie", "password", "secret", "token", "api_key", "api-key", "apikey"]
    if any(marker in lowered for marker in secret_markers):
        return "[redacted]"
    if isinstance(value, str) and lowered in {"content", "body", "request", "raw", "raw_request", "raw_response"}:
        encoded = value.encode("utf-8", errors="replace")
        return {
            "bytes": len(encoded),
            "sha256": hashlib.sha256(encoded).hexdigest(),
        }
    if isinstance(value, str) and lowered == "regex":
        encoded = value.encode("utf-8", errors="replace")
        return {
            "bytes": len(encoded),
            "sha256": hashlib.sha256(encoded).hexdigest(),
        }
    if isinstance(value, (str, int, float, bool)) or value is None:
        return value
    if isinstance(value, list):
        return [mcp_audit_argument_value(key, item) for item in value[:20]]
    if isinstance(value, dict):
        return {
            str(child_key): mcp_audit_argument_value(str(child_key), child_value)
            for child_key, child_value in sorted(value.items(), key=lambda row: str(row[0]))[:20]
        }
    return str(type(value).__name__)


def mcp_audit_arguments(arguments: dict[str, Any] | None) -> dict[str, Any]:
    return {
        str(key): mcp_audit_argument_value(str(key), value)
        for key, value in sorted((arguments or {}).items(), key=lambda row: str(row[0]))
    }


def redacted_error_summary(error: Any) -> dict[str, Any]:
    message = str(error)
    encoded = message.encode("utf-8", errors="replace")
    return {
        "type": type(error).__name__,
        "message_bytes": len(encoded),
        "message_sha256": hashlib.sha256(encoded).hexdigest(),
        "message_redacted": True,
    }


def mcp_audit_error(error: Any) -> dict[str, Any]:
    return redacted_error_summary(error)


def target_probe_lock_blocked_payload(*, target: str, error: Any, safety: str) -> dict[str, Any]:
    return {
        "generated_at": utc_now(),
        "status": "blocked",
        "target": target,
        "error": redacted_error_summary(error),
        "safety": safety,
    }


def remove_raw_history_artifact(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {
            "file": path.name,
            "status": "not-present",
        }
    try:
        size = path.stat().st_size
        path.unlink()
    except OSError as error:
        return {
            "file": path.name,
            "status": "failed",
            "error": redacted_error_summary(error),
        }
    return {
        "file": path.name,
        "status": "removed",
        "bytes": size,
    }


def mcp_action_audit_record(
    *,
    tool: str,
    arguments: dict[str, Any] | None,
    status: str,
    result_text: str | None = None,
    error: Any = None,
) -> dict[str, Any]:
    record: dict[str, Any] = {
        "at": utc_now(),
        "tool": tool,
        "status": status,
        "arguments": mcp_audit_arguments(arguments),
    }
    if result_text is not None:
        encoded = result_text.encode("utf-8", errors="replace")
        record["result"] = {
            "text_bytes": len(encoded),
            "text_sha256": hashlib.sha256(encoded).hexdigest(),
        }
    if error is not None:
        record["error"] = mcp_audit_error(error)
    return record


def append_mcp_action_audit(
    sync_artifact: dict[str, Any],
    *,
    tool: str,
    arguments: dict[str, Any] | None,
    status: str,
    result_text: str | None = None,
    error: Any = None,
) -> None:
    sync_artifact.setdefault("mcp_actions", []).append(
        mcp_action_audit_record(
            tool=tool,
            arguments=arguments,
            status=status,
            result_text=result_text,
            error=error,
        )
    )


def call_mcp_tool_with_audit(
    client: Any,
    audit_artifact: dict[str, Any],
    *,
    tool: str,
    arguments: dict[str, Any] | None,
) -> tuple[dict[str, Any], str]:
    try:
        result = client.call_tool(tool, arguments or {})
    except Exception as error:
        append_mcp_action_audit(
            audit_artifact,
            tool=tool,
            arguments=arguments,
            status="failed",
            error=error,
        )
        raise

    raw_text = mcp_tool_text(result)
    if result.get("isError"):
        append_mcp_action_audit(
            audit_artifact,
            tool=tool,
            arguments=arguments,
            status="failed",
            result_text=raw_text,
        )
        raise RuntimeError(raw_text)

    append_mcp_action_audit(
        audit_artifact,
        tool=tool,
        arguments=arguments,
        status="succeeded",
        result_text=raw_text,
    )
    return result, raw_text


def call_mcp_tool_with_audit_or_fallback(
    client: Any,
    audit_artifact: dict[str, Any],
    *,
    primary_tool: str,
    primary_arguments: dict[str, Any] | None,
    fallback_tool: str,
    fallback_arguments: dict[str, Any] | None,
) -> dict[str, Any]:
    primary_error_type = "unknown"
    try:
        result, raw_text = call_mcp_tool_with_audit(
            client,
            audit_artifact,
            tool=primary_tool,
            arguments=primary_arguments,
        )
        return {
            "tool": primary_tool,
            "arguments": primary_arguments or {},
            "result": result,
            "raw_text": raw_text,
            "fallback_used": False,
            "fallback_reason": None,
        }
    except Exception as primary_error:
        primary_error_type = type(primary_error).__name__
        fallback_reason = f"{primary_tool} failed ({primary_error_type}); using {fallback_tool} fallback"

    try:
        result, raw_text = call_mcp_tool_with_audit(
            client,
            audit_artifact,
            tool=fallback_tool,
            arguments=fallback_arguments,
        )
        return {
            "tool": fallback_tool,
            "arguments": fallback_arguments or {},
            "result": result,
            "raw_text": raw_text,
            "fallback_used": True,
            "fallback_reason": fallback_reason,
        }
    except Exception as fallback_error:
        raise RuntimeError(
            f"{primary_tool} failed ({primary_error_type}); "
            f"{fallback_tool} fallback failed ({type(fallback_error).__name__})"
        ) from fallback_error


def list_mcp_tools_with_audit(client: Any, audit_artifact: dict[str, Any]) -> list[str]:
    try:
        tools = client.list_tools()
    except Exception as error:
        append_mcp_action_audit(
            audit_artifact,
            tool="tools/list",
            arguments={},
            status="failed",
            error=error,
        )
        raise

    names = sorted_unique_strings([
        str(tool.get("name"))
        for tool in tools
        if isinstance(tool, dict) and tool.get("name") is not None
    ])
    append_mcp_action_audit(
        audit_artifact,
        tool="tools/list",
        arguments={},
        status="succeeded",
        result_text=json.dumps({"tools": names}, sort_keys=True),
    )
    return names


def call_mcp_history_tool_with_inventory(
    client: Any,
    audit_artifact: dict[str, Any],
    *,
    primary_tool: str,
    primary_arguments: dict[str, Any] | None,
    fallback_tool: str,
    fallback_arguments: dict[str, Any] | None,
    available_tools: list[str] | None,
) -> dict[str, Any]:
    if available_tools is None:
        history_read = call_mcp_tool_with_audit_or_fallback(
            client,
            audit_artifact,
            primary_tool=primary_tool,
            primary_arguments=primary_arguments,
            fallback_tool=fallback_tool,
            fallback_arguments=fallback_arguments,
        )
        history_read["selection_reason"] = "tools-list-unavailable"
        return history_read

    available_set = set(available_tools)
    if primary_tool in available_set:
        history_read = call_mcp_tool_with_audit_or_fallback(
            client,
            audit_artifact,
            primary_tool=primary_tool,
            primary_arguments=primary_arguments,
            fallback_tool=fallback_tool,
            fallback_arguments=fallback_arguments,
        )
        history_read["selection_reason"] = f"{primary_tool} listed by tools/list"
        return history_read

    if fallback_tool in available_set:
        result, raw_text = call_mcp_tool_with_audit(
            client,
            audit_artifact,
            tool=fallback_tool,
            arguments=fallback_arguments,
        )
        return {
            "tool": fallback_tool,
            "arguments": fallback_arguments or {},
            "result": result,
            "raw_text": raw_text,
            "fallback_used": True,
            "fallback_reason": f"{primary_tool} not listed by tools/list; using {fallback_tool} fallback",
            "selection_reason": "tools-list-primary-missing",
        }

    raise RuntimeError(f"Neither {primary_tool} nor {fallback_tool} is listed by Burp MCP tools/list")


BURP_MCP_REQUIRED_CAPABILITY_TOOLS = {
    "proxy-http-history": ["get_proxy_http_history_regex", "get_proxy_http_history"],
    "proxy-websocket-history": ["get_proxy_websocket_history_regex", "get_proxy_websocket_history"],
    "proxy-intercept-state": ["set_proxy_intercept_state"],
    "http-request-send": ["send_http1_request", "send_http2_request"],
    "repeater-tab": ["create_repeater_tab", "create_repeater_tab_http2"],
}


BURP_MCP_DISABLED_CAPABILITY_MARKERS = {
    "burp-scanner": ["scan", "scanner"],
    "intruder": ["intruder"],
    "burp-state-editing": [
        "set_project_options",
        "set_user_options",
        "set_task_execution_engine_state",
        "set_active_editor_contents",
    ],
}


def summarize_burp_mcp_tool_inventory(tool_names: list[str]) -> dict[str, Any]:
    names = sorted_unique_strings(tool_names)
    name_set = set(names)
    required: dict[str, dict[str, Any]] = {}
    available_required = 0
    for capability, required_tools in BURP_MCP_REQUIRED_CAPABILITY_TOOLS.items():
        available_tools = [name for name in required_tools if name in name_set]
        if available_tools:
            available_required += 1
        required[capability] = {
            "status": "available" if available_tools else "missing",
            "tools": required_tools,
            "available_tools": available_tools,
        }

    disabled: dict[str, dict[str, Any]] = {}
    lowered_names = {name: name.lower() for name in names}
    for capability, markers in BURP_MCP_DISABLED_CAPABILITY_MARKERS.items():
        matched_tools = [
            name
            for name, lowered in lowered_names.items()
            if any(marker in lowered for marker in markers)
        ]
        disabled[capability] = {
            "status": "available-but-disabled" if matched_tools else "not-present",
            "tools": sorted(matched_tools),
            "reason": "Not used by InferForge automation; high-volume or scanner-style tooling stays outside the safe loop.",
        }

    return {
        "tool_count": len(names),
        "tools": names,
        "required_capabilities": required,
        "required_summary": {
            "available": available_required,
            "missing": len(required) - available_required,
            "total": len(required),
        },
        "disabled_capabilities": disabled,
    }


def build_burp_mcp_tool_inventory(mcp_url: str, *, timeout: int = 5) -> dict[str, Any]:
    inventory: dict[str, Any] = {
        "status": "not-checked",
        "mcp_endpoint": mcp_url,
        "tool_count": 0,
        "tools": [],
        "required_capabilities": {},
        "required_summary": {
            "available": 0,
            "missing": len(BURP_MCP_REQUIRED_CAPABILITY_TOOLS),
            "total": len(BURP_MCP_REQUIRED_CAPABILITY_TOOLS),
        },
        "disabled_capabilities": {},
        "mcp_actions": [],
        "safety": "Read-only MCP tools/list inventory. It does not call Burp Scanner, send HTTP requests, fuzz, sign wallets, or submit transactions.",
    }
    try:
        with McpSseClient(mcp_url, timeout=timeout) as client:
            tools = client.list_tools()
    except Exception as error:
        inventory["status"] = "unavailable"
        inventory["error"] = redacted_error_summary(error)
        inventory["mcp_actions"].append(
            mcp_action_audit_record(
                tool="tools/list",
                arguments={},
                status="failed",
                error=error,
            )
        )
        return inventory

    names = [
        str(tool.get("name"))
        for tool in tools
        if tool.get("name") is not None
    ]
    inventory.update(summarize_burp_mcp_tool_inventory(names))
    inventory["status"] = "listed"
    inventory["mcp_actions"].append(
        mcp_action_audit_record(
            tool="tools/list",
            arguments={},
            status="succeeded",
            result_text=json.dumps({"tools": inventory["tools"]}, sort_keys=True),
        )
    )
    return inventory


def http_request(
    target: str,
    method: str,
    path: str,
    body: str | None = None,
    headers: dict[str, str] | None = None,
    timeout: int = 20,
) -> dict[str, Any]:
    url = urllib.parse.urljoin(target.rstrip("/") + "/", path.lstrip("/"))
    raw_body = None if body is None else body.encode("utf-8")
    req = urllib.request.Request(url, method=method, data=raw_body, headers=headers or {})
    started = time.monotonic()

    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            resp_body = resp.read(MAX_RESPONSE_BYTES + 1)
            response_headers = dict(resp.headers.items())
            status = resp.status
    except urllib.error.HTTPError as error:
        resp_body = error.read(MAX_RESPONSE_BYTES + 1)
        response_headers = dict(error.headers.items())
        status = error.code
    except urllib.error.URLError as error:
        return {
            "ok": False,
            "status": None,
            "duration_ms": round((time.monotonic() - started) * 1000),
            "error": str(error.reason),
            "body_sample": "",
            "body_text": "",
            "body_sha256": None,
            "body_truncated": False,
            "body_length": 0,
            "headers": {},
        }
    except (TimeoutError, socket.timeout) as error:
        return {
            "ok": False,
            "status": None,
            "duration_ms": round((time.monotonic() - started) * 1000),
            "error": str(error),
            "body_sample": "",
            "body_text": "",
            "body_sha256": None,
            "body_truncated": False,
            "body_length": 0,
            "headers": {},
        }

    body_truncated = len(resp_body) > MAX_RESPONSE_BYTES
    if body_truncated:
        resp_body = resp_body[:MAX_RESPONSE_BYTES]
    body_text = resp_body.decode("utf-8", errors="replace")

    return {
        "ok": True,
        "status": status,
        "duration_ms": round((time.monotonic() - started) * 1000),
        "error": None,
        "body_sample": body_text[:MAX_BODY_SAMPLE_CHARS],
        "body_text": body_text,
        "body_sha256": hashlib.sha256(resp_body).hexdigest(),
        "body_truncated": body_truncated,
        "body_length": len(resp_body),
        "headers": response_headers,
    }


def http_request_through_proxy(
    target: str,
    proxy: str,
    method: str,
    path: str,
    body: str | None = None,
    headers: dict[str, str] | None = None,
    timeout: int = 20,
) -> dict[str, Any]:
    target_url = urllib.parse.urljoin(target.rstrip("/") + "/", path.lstrip("/"))
    parsed_target = urllib.parse.urlparse(target_url)
    parsed_proxy = urllib.parse.urlparse(proxy)
    if parsed_target.scheme not in {"http", "https"} or not parsed_target.hostname:
        return {
            "ok": False,
            "status": None,
            "duration_ms": 0,
            "error": "burp-observe currently supports only HTTP or HTTPS targets",
            "body_sample": "",
            "body_text": "",
            "body_sha256": None,
            "body_truncated": False,
            "body_length": 0,
            "headers": {},
        }
    if parsed_proxy.scheme != "http" or not parsed_proxy.hostname:
        return {
            "ok": False,
            "status": None,
            "duration_ms": 0,
            "error": "proxy must be an http://host:port URL",
            "body_sample": "",
            "body_text": "",
            "body_sha256": None,
            "body_truncated": False,
            "body_length": 0,
            "headers": {},
        }

    request_headers = dict(headers or {})
    request_headers.setdefault("Host", parsed_target.netloc)
    request_headers.setdefault("Connection", "close")
    raw_body = None if body is None else body.encode("utf-8")
    if raw_body is not None:
        request_headers.setdefault("Content-Length", str(len(raw_body)))

    started = time.monotonic()
    if parsed_target.scheme == "https":
        conn = http.client.HTTPSConnection(
            parsed_proxy.hostname,
            parsed_proxy.port or 8080,
            timeout=timeout,
            context=ssl._create_unverified_context(),
        )
        conn.set_tunnel(parsed_target.hostname, parsed_target.port or 443)
        request_target = urllib.parse.urlunparse(
            ("", "", parsed_target.path or "/", "", parsed_target.query, "")
        )
    else:
        conn = http.client.HTTPConnection(
            parsed_proxy.hostname,
            parsed_proxy.port or 8080,
            timeout=timeout,
        )
        request_target = target_url
    try:
        conn.request(method, request_target, body=raw_body, headers=request_headers)
        resp = conn.getresponse()
        resp_body = resp.read(MAX_RESPONSE_BYTES + 1)
        response_headers = {key: value for key, value in resp.getheaders()}
        status = resp.status
    except (OSError, http.client.HTTPException) as error:
        return {
            "ok": False,
            "status": None,
            "duration_ms": round((time.monotonic() - started) * 1000),
            "error": str(error),
            "body_sample": "",
            "body_text": "",
            "body_sha256": None,
            "body_truncated": False,
            "body_length": 0,
            "headers": {},
        }
    finally:
        conn.close()

    body_truncated = len(resp_body) > MAX_RESPONSE_BYTES
    if body_truncated:
        resp_body = resp_body[:MAX_RESPONSE_BYTES]
    body_text = resp_body.decode("utf-8", errors="replace")

    return {
        "ok": True,
        "status": status,
        "duration_ms": round((time.monotonic() - started) * 1000),
        "error": None,
        "body_sample": body_text[:MAX_BODY_SAMPLE_CHARS],
        "body_text": body_text,
        "body_sha256": hashlib.sha256(resp_body).hexdigest(),
        "body_truncated": body_truncated,
        "body_length": len(resp_body),
        "headers": response_headers,
    }


def is_loopback_target(target: str) -> bool:
    hostname = urllib.parse.urlparse(target).hostname
    if not hostname:
        return False
    if hostname.lower() == "localhost":
        return True
    try:
        return ipaddress.ip_address(hostname).is_loopback
    except ValueError:
        return False


def render_profile_headers(headers: dict[str, Any], target: str) -> dict[str, str]:
    origin = origin_for(target)
    rendered = {}
    for key, value in headers.items():
        rendered[str(key)] = str(value).replace("{origin}", origin)
    return rendered


def build_burp_observation_plan(target: str, profile: dict[str, Any] | None = None) -> list[dict[str, Any]]:
    if profile and "burp_observation_plan" in profile:
        plan = []
        for index, item in enumerate(profile.get("burp_observation_plan") or []):
            if not isinstance(item, dict):
                raise ValueError(f"Invalid Burp observation entry at index {index}: expected object.")
            if not is_active_observation_item(item):
                continue
            label = active_observation_label(item, index)
            method = str(item.get("method") or "").upper()
            if method not in HTTP_METHODS:
                raise ValueError(f"Invalid active Burp observation `{label}`: unsupported method `{method or '(missing)'}`.")
            path_problem = concrete_local_path_problem(item.get("path"))
            if path_problem:
                raise ValueError(f"Invalid active Burp observation `{label}`: {path_problem}.")
            body = item.get("body")
            if "body_json" in item:
                body = json.dumps(item["body_json"])
            plan.append(
                {
                    "id": item.get("id") or f"burp_observe_{index}",
                    "method": method,
                    "path": item["path"],
                    "headers": render_profile_headers(item.get("headers", {}), target),
                    "body": body,
                    "expected_statuses": item.get("expected_statuses", []),
                    "cluster": item.get("cluster", "unknown"),
                }
            )
        return plan

    origin = origin_for(target)
    return [
        {
            "id": "burp_observe_health",
            "method": "GET",
            "path": "/health",
            "headers": {"User-Agent": "InferForge-Burp-Observe/0.1"},
            "body": None,
            "expected_statuses": [200],
            "cluster": "health",
        },
        {
            "id": "burp_observe_quote_invalid_body",
            "method": "POST",
            "path": "/api/quote",
            "headers": {
                "User-Agent": "InferForge-Burp-Observe/0.1",
                "Origin": origin,
                "Content-Type": "application/json",
            },
            "body": "{}",
            "expected_statuses": [400],
            "cluster": "quote",
        },
        {
            "id": "burp_observe_rpc_get_health",
            "method": "POST",
            "path": "/api/rpc/solana/devnet",
            "headers": {
                "User-Agent": "InferForge-Burp-Observe/0.1",
                "Origin": origin,
                "Content-Type": "application/json",
            },
            "body": json.dumps({"jsonrpc": "2.0", "id": 1, "method": "getHealth"}),
            "expected_statuses": [200],
            "cluster": "solana-rpc-http",
        },
        {
            "id": "burp_observe_orca_invalid_address",
            "method": "GET",
            "path": "/api/orca/pools/not-an-address",
            "headers": {"User-Agent": "InferForge-Burp-Observe/0.1"},
            "body": None,
            "expected_statuses": [400],
            "cluster": "orca-pools",
        },
    ]


def burp_history_host_regex(target: str) -> str | None:
    parsed = urllib.parse.urlparse(target)
    if not parsed.netloc:
        return None
    hosts = {parsed.netloc}
    if parsed.hostname:
        hosts.add(parsed.hostname)
        if parsed.port is None:
            if parsed.scheme == "https":
                hosts.add(f"{parsed.hostname}:443")
            elif parsed.scheme == "http":
                hosts.add(f"{parsed.hostname}:80")
    host_terms = "|".join(
        re.escape(host)
        for host in sorted(hosts, key=lambda item: (len(item), item), reverse=True)
    )
    return rf"Host:\s*(?:{host_terms})"


def build_burp_history_regex(
    target: str,
    observation_plan: list[dict[str, Any]],
    *,
    include_ws_upgrade: bool = False,
) -> str:
    signal_terms = []
    for item in observation_plan:
        user_agent = (item.get("headers") or {}).get("User-Agent")
        if user_agent:
            signal_terms.append(re.escape(f"User-Agent: {user_agent}"))
    if not signal_terms:
        signal_terms.extend(
            re.escape(f"{item['method']} {item['path']}")
            for item in observation_plan
        )
    if include_ws_upgrade:
        signal_terms.append(r"Upgrade:\s*websocket")
    signal_regex = "|".join(dict.fromkeys(signal_terms))
    host_regex = burp_history_host_regex(target)
    if not signal_regex:
        return host_regex or ""
    if not host_regex:
        return signal_regex
    return rf"(?:{host_regex}[\s\S]*(?:{signal_regex})|(?:{signal_regex})[\s\S]*{host_regex})"


def run_ws_upgrade_observation_through_proxy(
    target: str,
    proxy: str,
    node: str,
    source_root: Path,
    profile: dict[str, Any] | None = None,
) -> dict[str, Any]:
    ws_profile = websocket_observation_config(profile)
    if ws_profile is None:
        return {
            "id": "burp_observe_ws_upgrade",
            "ok": True,
            "skipped": True,
            "status": None,
            "path": None,
            "cluster": "solana-rpc-ws",
            "expected_statuses": [],
            "error": "WebSocket observation disabled by target profile.",
        }
    ws_path = str(ws_profile.get("path") or "")
    ws_cluster = str(ws_profile.get("cluster") or "solana-rpc-ws")
    ws_expected_statuses = list(ws_profile.get("expected_statuses") or [101])
    subscribe_method = str(ws_profile.get("subscribe_method") or "slotSubscribe")
    path_problem = concrete_local_path_problem(ws_path)
    if path_problem:
        return {
            "id": "burp_observe_ws_upgrade",
            "ok": False,
            "status": None,
            "path": ws_path,
            "cluster": ws_cluster,
            "expected_statuses": ws_expected_statuses,
            "error": f"WebSocket observation path is unsafe: {path_problem}",
        }
    node_path = Path(node)
    if not node_path.exists():
        fallback = command_result(["node", "-v"])
        if not fallback["ok"]:
            return {
                "id": "burp_observe_ws_upgrade",
                "ok": False,
                "status": None,
                "error": f"Node not found at {node}",
            }
        node = "node"

    parsed = urllib.parse.urlparse(target)
    if parsed.scheme != "http":
        return {
            "id": "burp_observe_ws_upgrade",
            "ok": False,
            "status": None,
            "error": "WebSocket upgrade observation currently supports HTTP targets only",
        }
    ws_url = urllib.parse.urlunparse(("ws", parsed.netloc, ws_path, "", "", ""))
    script = """
import fs from 'node:fs'
import { WebSocket } from 'ws'
import proxyAgentPkg from 'https-proxy-agent'

const { HttpsProxyAgent } = proxyAgentPkg
const input = JSON.parse(fs.readFileSync(0, 'utf8'))
const agent = new HttpsProxyAgent(input.proxy)
const started = Date.now()
let opened = false
let messageSeen = false

const ws = new WebSocket(input.url, {
  agent,
  headers: { Origin: input.origin },
  handshakeTimeout: 5000,
  perMessageDeflate: false,
})

const finish = (status, error = null) => {
  console.log(JSON.stringify({
    id: 'burp_observe_ws_upgrade',
    ok: opened,
    status,
    duration_ms: Date.now() - started,
    opened,
    message_seen: messageSeen,
    error,
  }))
  process.exit(opened ? 0 : 1)
}

const timer = setTimeout(() => {
  ws.terminate()
  finish(opened ? 101 : null, opened ? null : 'timeout')
}, 10000)

ws.on('open', () => {
  opened = true
  ws.send(JSON.stringify({ jsonrpc: '2.0', id: 1, method: input.subscribeMethod }))
  setTimeout(() => ws.close(1000, 'done'), 500)
})
ws.on('message', () => {
  messageSeen = true
  clearTimeout(timer)
  ws.close(1000, 'done')
})
ws.on('close', (code, reason) => {
  clearTimeout(timer)
  finish(opened ? 101 : null, opened ? null : `closed ${code} ${reason.toString()}`)
})
ws.on('error', (error) => {
  clearTimeout(timer)
  finish(opened ? 101 : null, error.message)
})
"""
    if not source_root.is_dir():
        return {
            "id": "burp_observe_ws_upgrade",
            "ok": False,
            "status": None,
            "error": f"Source root not found: {source_root}",
        }

    proc = subprocess.run(
        [node, "--input-type=module", "--eval", script],
        cwd=str(source_root),
        input=json.dumps(
            {
                "url": ws_url,
                "proxy": proxy,
                "origin": origin_for(target),
                "subscribeMethod": subscribe_method,
            }
        ),
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT,
        timeout=15,
        check=False,
    )

    parsed_output = parse_json_object(proc.stdout.strip().splitlines()[-1] if proc.stdout.strip() else "")
    if parsed_output:
        parsed_output["path"] = ws_path
        parsed_output["method"] = "WS"
        parsed_output["cluster"] = ws_cluster
        parsed_output["expected_statuses"] = ws_expected_statuses
        return parsed_output
    return {
        "id": "burp_observe_ws_upgrade",
        "ok": False,
        "status": None,
        "path": ws_path,
        "method": "WS",
        "cluster": ws_cluster,
        "expected_statuses": ws_expected_statuses,
        "error": proc.stdout[-1000:],
    }


def compact_response_attempt(response: dict[str, Any]) -> dict[str, Any]:
    return {
        "status": response.get("status"),
        "duration_ms": response.get("duration_ms"),
        "error": response.get("error"),
        "body_sha256": response.get("body_sha256"),
        "body_sample": response.get("body_sample", "")[:240],
    }


@dataclass(frozen=True)
class Probe:
    id: str
    label: str
    method: str
    path: str
    body: str | None = None
    origin: str | None = None
    content_type: str | None = None
    expected_statuses: tuple[int, ...] = ()
    category: str = "http"
    external: bool = False
    policy_field: str | None = None
    risk: str = "safe"
    referer: str | None = None
    expectation: str = "status"
    strategy_set: str | None = None


def build_probe_headers(probe: Probe) -> dict[str, str]:
    headers: dict[str, str] = {"User-Agent": "InferForge-Local/0.1"}
    if probe.origin:
        headers["Origin"] = probe.origin
    if probe.referer:
        headers["Referer"] = probe.referer
    if probe.content_type:
        headers["Content-Type"] = probe.content_type
    if probe.method == "OPTIONS":
        headers["Access-Control-Request-Method"] = "POST"
        headers["Access-Control-Request-Headers"] = "content-type"
    return headers


def is_next_dev_manifest_error(response: dict[str, Any]) -> bool:
    if response.get("status") != 500:
        return False
    body = response.get("body_text") or response.get("body_sample") or ""
    return (
        "loadManifest" in body
        and "Unexpected end of JSON input" in body
        and ("next-dev-server" in body or "/_error" in body)
    )


def retry_reason_for_probe_response(probe: Probe, response: dict[str, Any]) -> str | None:
    if probe.external:
        return None
    is_generic_nextjs_route = str(probe.risk).startswith("safe-generic-route-")
    if probe.category not in {"quote", "solana-rpc-http", "orca-pools"} and not is_generic_nextjs_route:
        return None
    if response.get("status") is None:
        return "local-request-timeout-or-transport-error"
    if is_next_dev_manifest_error(response):
        return "next-dev-manifest-transient-500"
    return None


def run_probe_request(
    target: str,
    probe: Probe,
    *,
    timeout: int = 20,
    max_attempts: int = 1,
) -> tuple[dict[str, Any], list[dict[str, Any]], str | None]:
    attempts = []
    retry_reason = None
    response: dict[str, Any] | None = None
    headers = build_probe_headers(probe)

    for attempt_number in range(1, max_attempts + 1):
        response = http_request(
            target=target,
            method=probe.method,
            path=probe.path,
            body=probe.body,
            headers=headers,
            timeout=timeout,
        )
        attempts.append({"attempt": attempt_number, **compact_response_attempt(response)})
        retry_reason = retry_reason_for_probe_response(probe, response)
        if retry_reason is None or attempt_number == max_attempts:
            break
        time.sleep(0.4)

    if response is None:
        raise RuntimeError("probe request produced no response")
    return response, attempts, retry_reason if len(attempts) > 1 else None


def jsonrpc_response_is_error_only(value: Any) -> bool:
    responses = value if isinstance(value, list) else [value]
    if not responses:
        return False

    for item in responses:
        if not isinstance(item, dict):
            return False
        if "result" in item:
            return False
        if "error" not in item:
            return False
    return True


def response_has_internal_error_leak(response: dict[str, Any]) -> bool:
    body = response.get("body_text") or response.get("body_sample") or ""
    lowered = body.lower()
    return any(
        marker in lowered
        for marker in [
            "traceback",
            "syntaxerror:",
            "typeerror:",
            "referenceerror:",
            "at async",
            "node_modules",
            "webpack-internal",
        ]
    )


def evaluate_probe_response(
    probe: Probe,
    status: int | None,
    response: dict[str, Any],
) -> tuple[bool, str]:
    if probe.expectation == "jsonrpc-error-or-local-reject":
        if status in {400, 403, 413, 415}:
            return True, "local-reject"
        if status != 200:
            return False, "expected local rejection or JSON-RPC error"
        if response_has_internal_error_leak(response):
            return False, "internal-error-leak"
        try:
            payload = json.loads(response.get("body_text") or "")
        except json.JSONDecodeError:
            return False, "invalid-json-rpc-response-body"
        if jsonrpc_response_is_error_only(payload):
            return True, "jsonrpc-error"
        return False, "jsonrpc-result-for-invalid-transaction-payload"

    if not probe.expected_statuses:
        return True, "status-unconstrained"
    if status in probe.expected_statuses:
        return True, "status"
    return False, "unexpected-status"


