    if args.discover_child_runs:
        check_dirs.extend(discover_harness_loop_dirs(artifact_dir))
    deduped_dirs = []
    seen_dirs: set[str] = set()
    for check_dir in check_dirs:
        resolved = check_dir.resolve()
